head.script:
//===================================================
// id       : se_105_01_04b
// 이름     : House B/L Freight
// 경로     : /ui/il/seaout/sobl/se_105_01_04b.xml
// 사용계정 : 
// 파라미터 :
//            IN  : 
//            OUT : 
//
// 비고     : 
//           
// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     : 
//===================================================
// JSP 전역 변수 → scwin 네임스페이스
scwin.p_lobranCd = "";
scwin.p_lobranNm = "";
scwin.userId = "";
scwin.p_seaExgbEx = "";
scwin.p_clntNo = "";

scwin.statusFlag = "";	//수정/등록 Flag(C:Regist, U:Update,I:Init)
scwin.processFlag = "";
scwin.invoiceCheck = "0";
scwin.tabNo = 0;
scwin.mhnoFlag = "0"; // 1일때 mhno onloadComplete후 조회.
scwin.exRateCheck = "1"; // 환율 존재 유무 
scwin.exRate1 = "0"; // 환율1  
scwin.exRate2 = "0"; // 환율2  
scwin.crc = ""; // 환종	  
scwin.v_linkcheck = ""; //"<%=p_linkcheck%>";
scwin.v_kcomcd = ""; //"<%=p_kcomcd%>";
scwin.v_blno = ""; //"<%=p_blno%>";
scwin.v_mhno = ""; //"<%=p_mhno%>";
scwin.v_bkno = ""; //"<%=p_bkno%>";

scwin.p_no = "";
scwin.p_row_cnt = "";
scwin.p_data = "";
scwin.p_hblno = "";
scwin.p_docuno = "";

scwin.strCurDate = "";

//hidden 컴포넌트
scwin.hd_kcomcd = "DBEX";
scwin.hd_hhio = "O";
scwin.hd_hhitem = "";
scwin.hd_creadyDt = "";
scwin.hd_hhpcgb = "";
scwin.hd_hhdanggb = "";
scwin.hd_commcustomer = "999999";

scwin.buyingSetting = "";


// onpageload
scwin.onpageload = async function () { };

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () {

    // 세션 정보
    let memJson = $c.data.getMemInfo();

    scwin.userId = memJson.userId;
    scwin.p_lobranCd = $c.data.getMemInfo("lobranCd") || "";  // 귀속부서코드
    scwin.p_lobranNm = $c.data.getMemInfo("lobranNm");  // 귀속부서 명

    //default 동부국제물류
    var resData = await $c.gus.dsCommonUtil("getCompanyInfoDTO", scwin.p_lobranCd)[0]?.value.split("\n");
    var commDTO = resData.reduce((acc, curr) => {
        let match = curr.match(/^\s*\w+\s+(\w+)\s+=\s+\[(.*)\]/);

        if (match) {
            let key = match[1];
            let value = match[2];

            if (value == "null") value = null;
            acc[key] = value;
        }

        return acc;
    }, {});

    scwin.p_clntNo = commDTO.clntNo || "";
    scwin.p_seaExgbEx = commDTO.seaExgbEx || "";

    scwin.v_linkcheck = $c.data.getParameter("linkcheck") || "";
    scwin.v_kcomcd = $c.data.getParameter("kcomcd") || "";
    scwin.v_blno = $c.data.getParameter("blno") || "";
    scwin.v_mhno = $c.data.getParameter("mhno") || "";
    scwin.v_bkno = $c.data.getParameter("bkno") || "";

    scwin.p_no = $c.data.getParameter("no") || "";
    scwin.p_row_cnt = $c.data.getParameter("row_cnt") || "";
    scwin.p_data = $c.data.getParameter("data") || "";
    scwin.p_hblno = $c.data.getParameter("hblno") || "";
    scwin.p_docuno = $c.data.getParameter("docuno") || "";

    // 서버일자
    scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");

    scwin.f_initSetTab(); //tab세팅	
    scwin.f_DefaultValue();

    scwin.f_ContainerTypeLoading();  // Container Type 정보 
    scwin.f_CurrencyLoading(); //환율 코드 정보.
    scwin.f_getParametrSetting(scwin.v_linkcheck); // link처리 
};

//---------------------------------------------------------
// Parameter Setting (WebSquare 표준 정리)
// - 컴포넌트 방어코드 제거
// - DataList API 통일: getRowCount / insertRow / setCellData
//---------------------------------------------------------
scwin.f_getParametrSetting = async function (gubun) {
    switch (gubun) {
        case "0":
            break;

        case "5": // House B/L에서 옴.
            scwin.mhnoFlag = "1";

            if ($c.gus.cfIsNull(scwin.v_blno)) {
                cnd_ed_hhblno.setValue("");
                cnd_ed_hhblno.focus();
                return false;
            }

            scwin.hd_kcomcd = scwin.v_kcomcd;
            cnd_ed_hhblno.setValue(scwin.v_blno);

            if (ds_hmhno.getRowCount() == 0) {
                ds_hmhno.insertRow(0);
            }

            const row = ds_hmhno.getRowCount() - 1;
            ds_hmhno.setCellData(row, "code", scwin.v_mhno);
            ds_hmhno.setCellData(row, "name", scwin.v_mhno);

            cnd_lc_mhno.focus();
            break;

        case "9":
            scwin.mhnoFlag = "1";
            cnd_ed_hhblno.setValue(scwin.p_hblno);

            if (ds_hmhno.getRowCount() == 0) {
                ds_hmhno.insertRow(0);
            }

            const r2 = ds_hmhno.getRowCount() - 1;
            ds_hmhno.setCellData(r2, "code", scwin.p_docuno);
            ds_hmhno.setCellData(r2, "name", scwin.p_docuno);

            cnd_lc_mhno.focus();
            break;

        default:
            break;
    }

    return true;
};

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function () {
    /*scwin.f_setDSHeader(dma_retrieve, "1");
    scwin.f_setDSHeader(ds_houseblList, "2");
    scwin.f_setDSHeader(ds_selling, "3");
    scwin.f_setDSHeader(ds_partner, "4");
    scwin.f_setDSHeader(ds_buying, "5");
    scwin.f_setDSHeader(ds_retrieveTariff, "6");
    scwin.f_setDSHeader(ds_resultTariff, "7");
    scwin.f_setDSHeader(ds_hmhno, "8");
    scwin.f_setDSHeader(ds_linecode, "9");
    scwin.f_setDSHeader(ds_frtMapping, "10");
    scwin.f_setDSHeader(ds_line_condition, "11");
    */

    scwin.f_Set("INIT");
    tac_tabMain.setSelectedTabIndex(0);

    cnd_ed_hhblno.focus();
};

//---------------------------------------------------------
// Tab 초기화
//---------------------------------------------------------
scwin.f_initSetTab = function () {
    //$c.gus.cfEnableObjects([tr_tab_center0, tr_tab_center1,tr_tab_center2]);
    // WebSquare 에서는 탭 컨트롤 사용
    tac_tabMain.setSelectedTabIndex(0);
    scwin.f_selectTabMenu(0);
};

//---------------------------------------------------------
// Tab Menu 선택 처리
//---------------------------------------------------------
scwin.f_selectTabMenu = function (idx) {
    scwin.tabNo = idx;
    dma_retrieve.set("tabIndex", String(idx));
};

//---------------------------------------------------------
// 화면상태 세팅
//--------------------------------------------------------- 
scwin.f_Set = function (gubun) {
    switch (gubun) {
        case "INIT": // 초기화
            $c.gus.cfDisableKeyData();  // Key와 Data를 모두 disable(non-editable)
            $c.gus.cfDisableBtnOnly([
                btn_Cancel, btn_Save, btn_Delete, btn_Update,
                btn_1, btn_3, btn_4, btn_5, btn_6, btn_exChg, btn_cusChg,
                btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_DelAll1,
                btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_DelAll2,
                btn_AddRow3, btn_DelRow3, btn_CancelRow3, btn_DelAll3
            ]);
            $c.gus.cfEnableBtnOnly([btn_7]);
            scwin.f_DisablePopUpObj();
            $c.gus.cfEnableObjects([tbl_searchCondition, tbl_searchCondition2]); // 조회조건
            scwin.statusFlag = "I";
            break;

        case "RETRIEVE": // 조회모드
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([
                btn_Save, btn_Cancel, btn_1, btn_exChg, btn_cusChg,
                btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_DelAll1,
                btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_DelAll2,
                btn_AddRow3, btn_DelRow3, btn_CancelRow3, btn_DelAll3
            ]);
            $c.gus.cfEnableBtnOnly([
                btn_Delete, btn_3, btn_4, btn_5, btn_6, btn_7
            ]);

            // 그리드 수정 불가
            // gr_selling.readOnly = true;
            // gr_partner.readOnly = true;
            // gr_buying.readOnly = true;

            scwin.f_setGridColumnsReadOnly(gr_selling, true);
            scwin.f_setGridColumnsReadOnly(gr_partner, true);
            scwin.f_setGridColumnsReadOnly(gr_buying, true);

            if (scwin.statusFlag == "C") {
                $c.gus.cfDisableBtnOnly([btn_Update]);
            } else {
                $c.gus.cfEnableBtnOnly([btn_Update]);
            }

            $c.gus.cfEnableObjects([tbl_searchCondition, tbl_searchCondition2]); // 조회조건
            scwin.statusFlag = "";
            break;

        case "CREATE": // 신규
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([
                btn_Update, btn_Delete, btn_3, btn_4, btn_5, btn_6
            ]);
            $c.gus.cfEnableBtnOnly([
                btn_Save, btn_Cancel, btn_1, btn_7, btn_exChg, btn_cusChg,
                btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_DelAll1,
                btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_DelAll2,
                btn_AddRow3, btn_DelRow3, btn_CancelRow3, btn_DelAll3
            ]);

            // 그리드 수정 가능
            // gr_selling.readOnly = false;
            // gr_partner.readOnly = false;
            // gr_buying.readOnly = false;

            scwin.f_setGridColumnsReadOnly(gr_selling, false);
            scwin.f_setGridColumnsReadOnly(gr_partner, false);
            scwin.f_setGridColumnsReadOnly(gr_buying, false);

            $c.gus.cfDisableObjects([tbl_searchCondition, tbl_searchCondition2]); // 조회조건
            scwin.statusFlag = "C";
            break;

        case "UPDATE":
            $c.gus.cfDisableBtnOnly([
                btn_Update, btn_Delete, btn_3, btn_4, btn_5, btn_6
            ]);
            $c.gus.cfEnableBtnOnly([
                btn_Save, btn_Cancel, btn_1, btn_7, btn_exChg, btn_cusChg,
                btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_DelAll1,
                btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_DelAll2,
                btn_AddRow3, btn_DelRow3, btn_CancelRow3, btn_DelAll3
            ]);

            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();

            // 그리드 수정 가능
            // gr_selling.Editable  = "true";
            // gr_partner.Editable  = "true"; 
            // gr_buying.Editable  = "true";  
            scwin.f_setGridColumnsReadOnly(gr_selling, false);
            scwin.f_setGridColumnsReadOnly(gr_partner, false);
            scwin.f_setGridColumnsReadOnly(gr_buying, false);

            $c.gus.cfDisableObjects([tbl_searchCondition, tbl_searchCondition2]); // 조회조건
            scwin.statusFlag = "U";
            break;

        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Delete, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Update]);
            scwin.f_Set("RETRIEVE");
            break;
    }
};

//-------------------------------------------------------------------------
// PopUp 이미지 enable/disable (JSP에서는 이미지 컴포넌트)
// WebSquare 퍼블리싱에서는 trigger 로 되어 있으므로 [TODO] 필요시 제어
//-------------------------------------------------------------------------
scwin.f_EnablePopUpObj = function () {
    $c.gus.cfEnableObjects([ed_hhcurdt, ed_hhetd]);
    $c.gus.cfEnableObjects([img_PopUp1, img_PopUp2, img_PopUp3, img_PopUp4, img_PopUp5, img_PopUp6, img_PopUp7, img_PopUp8, img_PopUp9]);
};
scwin.f_DisablePopUpObj = function () {
    $c.gus.cfDisableObjects([ed_hhcurdt, ed_hhetd]);
    $c.gus.cfDisableObjects([img_PopUp1, img_PopUp2, img_PopUp3, img_PopUp4, img_PopUp5, img_PopUp6, img_PopUp7, img_PopUp8, img_PopUp9]);
};

//---------------------------------------------------------
// 조회
//---------------------------------------------------------
scwin.f_Retrieve = async function () {
    if (cnd_ed_hhblno.getValue() == null || cnd_ed_hhblno.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House No"]);  // @은(는) 필수 입력 항목입니다.
        return;
    }

    cnd_lc_mhno.focus(); // B/L No 빠져나올때 event처리 

    dma_retrieve.set("hhblno", cnd_ed_hhblno.getValue());
    dma_retrieve.set("hhblno2", srch_ed_hhblno.getValue());
    dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
    dma_retrieve.set("mhno", cnd_lc_mhno.getValue());
    dma_retrieve.set("hhio", scwin.hd_hhio);

    ds_houseblList.removeAll();
    ds_buying.removeAll();
    ds_selling.removeAll();
    ds_partner.removeAll();

    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 조회 후 처리 + (v_linkcheck==9) buying row 매핑 추가 (WebSquare 변환본)
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = async function (e) {
    //===========
    // 1) houseblList 결과 체크
    //===========
    if (ds_houseblList.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.
        scwin.f_Set("INIT");
        return false;
    } else {
        ds_houseblList.setRowPosition(0)
        $c.gus.cfEnableObj(cnd_ed_hhblno, true);
        $c.gus.cfEnableObj(cnd_lc_mhno, true);

        //tobe추가
        scwin.hd_creadyDt = ds_houseblList.getCellData(0, "creadyDt");

        // 그리드 헤더 체크 해제는 gridView 옵션으로 처리 [TODO]
        gr_buying.setHeaderValue('chk', false, false);
        gr_partner.setHeaderValue('chk', false, false);
        gr_selling.setHeaderValue('chk', false, false);

        //ds_profit.ClearData(); → WebSquare
        ds_profit.removeAll();

        $c.sbm.execute(sbm_RetrieveProfit);

        scwin.f_invoiceCheck(); // invoice Check
        scwin.f_Set("RETRIEVE");

        //tobe추가 : 셀렉트박스에 없는 항목이 있다면 셀렉트박스에 값 넣어주기 (selectdData = false 속성으로 대체)
        // e.responseJSON.OUT_DS2.forEach(function (rowJson, index) {
        //     if (ds_sellingUnit.getMatchedJSON("name", rowJson.fareUnit).length == 0) {
        //         ds_sellingUnit.setRowJSON(0, { "name": rowJson.fareUnit, "code": rowJson.fareUnit });
        //     }
        //     ds_selling.setCellData(index, "fareUnit", rowJson.fareUnit);
        // });
        // e.responseJSON.OUT_DS3.forEach(function (rowJson, index) {
        //     if (ds_partnerUnit.getMatchedJSON("name", rowJson.fareUnit).length == 0) {
        //         ds_partnerUnit.setRowJSON(0, { "name": rowJson.fareUnit, "code": rowJson.fareUnit });
        //     }
        //     ds_partner.setCellData(index, "fareUnit", rowJson.fareUnit);
        // });
        // e.responseJSON.OUT_DS4.forEach(function (rowJson, index) {
        //     if (ds_buyingUnit.getMatchedJSON("name", rowJson.fareUnit).length == 0) {
        //         ds_buyingUnit.setRowJSON(0, { "name": rowJson.fareUnit, "code": rowJson.fareUnit });
        //     }
        //     ds_buying.setCellData(index, "fareUnit", rowJson.fareUnit);
        // });

        scwin.f_SellingSum();
        scwin.f_PartnerSum();
        scwin.f_BuyingSum();

        if (tac_tabMain.getSelectedTabIndex() == 0) {
            gr_selling.setFocusedCell(0, 0);
        }
        if (tac_tabMain.getSelectedTabIndex() == 1) {
            gr_partner.setFocusedCell(0, 0);
        }
        if (tac_tabMain.getSelectedTabIndex() == 2) {
            gr_buying.setFocusedCell(0, 0);
        }
    }

    //scwin.f_Set("UPDATE");


    //===========
    // 2) linkcheck==9 이면 buying 데이터 추가
    //===========
    if (scwin.v_linkcheck != "9") {
        return true;
    }

    scwin.f_Set("UPDATE");

    var no = scwin.p_no;
    var row_cnt = parseInt(scwin.p_row_cnt, 10) || 0;
    var data = scwin.p_data || "";

    if (!data) return false;

    // data: "A_B_C$D_E_F..." 형태 가정
    var rtnValues = data.split("$");
    if (!rtnValues || rtnValues.length == 0) return false;

    // row_cnt만큼만 파싱 (data가 더 짧으면 실제 길이만)
    var loopCnt = Math.min(row_cnt, rtnValues.length);

    // 2차원 배열로 변환
    // [ [fromCd, crcCd, pchsAmtFcrc, exRate, pchsAmt, chgWt, pchsUpr], ... ]
    var rows = [];
    for (var t = 0; t < loopCnt; t++) {
        rows[t] = String(rtnValues[t] || "").split("_");
    }

    // 기존 buying 행 개수
    var k = ds_buying.getRowCount();



    //===========
    // 4) 반복: row 추가 + 매핑조회 + 데이터 세팅
    //===========
    for (var idx = 0; idx < rows.length; idx++) {

        var arr = rows[idx];
        if (!arr || arr.length < 7) continue;

        var fromCd = String(arr[0] || "").trim();
        var crcCd = String(arr[1] || "").trim();
        var amtFcrc = arr[2];
        var exRate = arr[3];
        var pchsAmt = arr[4];
        var chgWt = arr[5];
        var pchsUpr = arr[6];

        // (프로젝트 표준) buying에 row 1건 추가
        // - 표준 f_addRow(3)가 있으면 그대로 쓰는게 안전
        scwin.f_addRow(3);

        // 새로 추가된 row index (보통 마지막)
        var row = ds_buying.getRowCount() - 1;
        if (row < 0) continue;

        // pchsSeq = 이전행 + 1
        var prevRow = row - 1;
        var prevSeq = 0;
        if (prevRow >= 0) {
            prevSeq = Number(ds_buying.getCellData(prevRow, "pchsSeq") || 0);
        }
        ds_buying.setCellData(row, "pchsSeq", prevSeq + 1);

        // line_condition 세팅 (GAUCE 1행 → WebSquare 0행)
        ds_line_condition.setCellData(0, "hhliner", ed_hhliner ? ed_hhliner.getValue() : "");
        ds_line_condition.setCellData(0, "fromCd", fromCd);

        // tr_retrieve_frtMapping.post() 대체: submission 실행 후 결과 대기
        await scwin.f_frtMappingAsync();

        // ds_frtMapping 0행 결과 반영
        ds_buying.setCellData(row, "fareEngCd", ds_frtMapping.getCellData(0, "toCd"));
        ds_buying.setCellData(row, "fareEngNm", ds_frtMapping.getCellData(0, "description"));
        ds_buying.setCellData(row, "selpchItemCd", ds_frtMapping.getCellData(0, "dtlCd1"));
        ds_buying.setCellData(row, "fareGrpCd", ds_frtMapping.getCellData(0, "dtlCd2"));
        ds_buying.setCellData(row, "vatYn", ds_frtMapping.getCellData(0, "dtlCd3"));

        // 원본 데이터 세팅
        ds_buying.setCellData(row, "crcCd", crcCd);
        ds_buying.setCellData(row, "pchsAmtFcrc", amtFcrc);
        ds_buying.setCellData(row, "exRate", exRate);
        ds_buying.setCellData(row, "pchsAmt", pchsAmt);
        ds_buying.setCellData(row, "chgWt", chgWt);
        ds_buying.setCellData(row, "pchsUpr", pchsUpr);

        // USD면 usdAmt = pchsAmtFcrc
        if (crcCd == "USD") {
            ds_buying.setCellData(row, "usdAmt", amtFcrc);
        }
    }

    // 탭 이동 (프로젝트 공통함수 우선)
    tac_tabMain.setSelectedTabIndex(2)
    ds_houseblList.setRowPosition(0);

};

//===========
// 3) frtMapping 조회 Promise 래퍼
//  - sbm_retrieve_frtMapping onsubmitdone에서 resolve 필요
//===========
scwin.f_frtMappingAsync = function () {
    return new Promise(function (resolve, reject) {
        scwin._frtMapResolve = resolve;
        scwin._frtMapReject = reject;

        // ✅ 프로젝트 실제 submission ID로 교체
        $c.sbm.execute(sbm_retrieve_frtMapping);
    });
}
//-------------------------------------------------------------------------
// ✅ sbm_retrieve_frtMapping onsubmitdone에서 resolve 호출 (필수)
//-------------------------------------------------------------------------
scwin.sbm_retrieve_frtMapping_onsubmitdone = function (e) {
    if (typeof scwin._frtMapResolve == "function") {
        scwin._frtMapResolve(true);
    }
    scwin._frtMapResolve = null;
    scwin._frtMapReject = null;
};



//---------------------------------------------------------
// 조회(하단)
//---------------------------------------------------------
scwin.f_Retrieve2 = async function () {
    var e = "";
    //상단을 조회하지 않았거나, 결과값이 없을 경우
    if (ds_houseblList.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_018, ["Exchange Rate Information", "상단의 Search"]);  // @이(가) 존재하지 않습니다.\n먼저 @을(를) 하십시오.
        return;
    }

    if (srch_ed_hhblno.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House No"]);  // @은(는) 필수 입력 항목입니다.
        return;
    }
    cnd_lc_mhno2.focus(); // B/L No 빠져나올때 event처리 .

    //tobe추가 
    dma_retrieve.set("hhblno", cnd_ed_hhblno.getValue());
    dma_retrieve.set("hhblno2", srch_ed_hhblno.getValue());
    dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
    dma_retrieve.set("mhno", cnd_lc_mhno2.getValue());
    dma_retrieve.set("hhio", scwin.hd_hhio);

    //텝의 인덱스가 없다면 "0"으로 기본설정
    if (dma_retrieve.get("tabIndex") == "") {
        dma_retrieve.set("tabIndex", "0");
    }

    //실행.
    var idx = dma_retrieve.get("tabIndex");

    switch (idx) {
        case "0":
            //기존에 조회된 행이 있다면 재조회 안되도록함 개별검색은 재조회 가능
            if (ds_selling.getRowCount() > 0 && ds_selling.getCellData(ds_selling.getRowPosition(), "tabIndex") == "") {
                await $c.win.alert("조회된 Selling데이터가 있습니다.\nSelling데이터가 0건일 경우 조회가능합니다.");
            } else {
                e = await $c.sbm.execute(sbm_retrieveSelling);
                //selectdData = false 속성으로 대체
                // if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
                //     e.responseJSON.OUT_DS1.forEach(function (rowJson, index) {
                //         if (ds_sellingUnit.getMatchedJSON("name", rowJson.fareUnit).length == 0) {
                //             ds_sellingUnit.setRowJSON(0, { "name": rowJson.fareUnit, "code": rowJson.fareUnit });
                //         }
                //         ds_selling.setCellData(index, "fareUnit", rowJson.fareUnit);
                //     });
                // }
            }
            break;
        case "1":
            if (ds_partner.getRowCount() > 0 && ds_partner.getCellData(ds_partner.getRowPosition(), "tabIndex") == "") {
                await $c.win.alert("조회된 Partner데이터가 있습니다.\nPartner데이터가 0건일 경우 조회가능합니다.");
            } else {
                e = await $c.sbm.execute(sbm_retrievePartner);
                if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
                    //selectdData = false 속성으로 대체
                    // e.responseJSON.OUT_DS1.forEach(function (rowJson, index) {
                    //     if (ds_partnerUnit.getMatchedJSON("name", rowJson.fareUnit).length == 0) {
                    //         ds_partnerUnit.setRowJSON(0, { "name": rowJson.fareUnit, "code": rowJson.fareUnit });
                    //     }
                    //     ds_partner.setCellData(index, "fareUnit", rowJson.fareUnit);
                    // });
                }
            }
            break;
        case "2":
            if (ds_buying.getRowCount() > 0 && ds_buying.getCellData(ds_buying.getRowPosition(), "tabIndex") == "") {
                await $c.win.alert("조회된 Buying데이터가 있습니다.\nBuying데이터가 0건일 경우 조회가능합니다.");
            } else {
                scwin.buyingSetting = "caseRetrieve2";
                e = await $c.sbm.execute(sbm_retrieveBuying);
                //selectdData = false 속성으로 대체
                // if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
                //     e.responseJSON.OUT_DS1.forEach(function (rowJson, index) {
                //         if (ds_buyingUnit.getMatchedJSON("name", rowJson.fareUnit).length == 0) {
