//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = async function () {
    if (!cnd_ed_hhblno || cnd_ed_hhblno.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); // 해당하는 자료가 존재하지 않습니다
        return;
    } else {
        scwin.f_Set("UPDATE");
        if (ed_hhcur.getValue().trim() == "") ed_hhcur.setValue("USD");
        if (lc_hhexgb.getValue() == "") {
            lc_hhexgb.setValue(scwin.p_seaExgbEx);
        }

        if (ed_hhcurdt.getValue().trim() == "") {
            ed_hhcurdt.setValue(ed_hhetd.getValue());
        }
    }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    if (ds_houseblList.getModifiedIndex().length > 0
        || ds_selling.getModifiedIndex().length > 0
        || ds_partner.getModifiedIndex().length > 0
        || ds_buying.getModifiedIndex().length > 0) {
        if (await scwin.f_validate() && await scwin.f_JobCloseYn()) {
            if (await $c.win.confirm($c.data.getMessage(E_MSG_CM_CRM_001))) { //저장하시겠습니까?	
                if (scwin.statusFlag == "C") {
                    if (ds_houseblList.getRowCount() == 0) ds_houseblList.insertRow(0);
                    var r = ds_houseblList.getRowPosition();

                    ds_houseblList.setValue(r, "kcomcd", scwin.hd_kcomcd);
                    ds_houseblList.setValue(r, "hhblno", cnd_ed_hhblno ? cnd_ed_hhblno.getValue() : "");
                    ds_houseblList.setValue(r, "mhno", cnd_lc_mhno ? cnd_lc_mhno.getValue() : "");
                    ds_houseblList.setValue(r, "hhio", scwin.hd_hhio);
                    ds_houseblList.setValue(r, "inpid", scwin.userId);
                }
                scwin.v_linkcheck = "";
                var e = await $c.sbm.execute(sbm_save);
                if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
                    await $c.gus.cfAlertMsg(E_MSG_CM_INF_001); //  성공적으로 저장하였습니다.
                    $c.gus.cfEnableObj(cnd_ed_hhblno, true);
                    $c.gus.cfEnableObj(cnd_lc_mhno, true);
                    await scwin.f_Retrieve();
                    scwin.f_Set("SAVE")
                }
            }
        }
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["House B/L Freight"]); // @은(는) 변경된 사항이 없습니다.
    }
};

//-------------------------------------------------------------------------
