scwin.f_Cancel = function () {
    $c.gus.cfEnableObj(cnd_ed_hhblno, true);
    $c.gus.cfEnableObj(cnd_lc_mhno, true);

    cnd_ed_hhblno.focus();

    scwin.f_Set("RETRIEVE");

    $c.data.undoAll(ds_houseblList);

    //tobe추가 : 행추가해서 생긴 행은 취소하면 화면에서 삭제됨.
    var creatRow = ds_selling.getRowIndexByStatus("C");
    ds_selling.removeRows(creatRow);

    scwin.f_cancelRow(1);
    scwin.f_cancelRow(2);
    scwin.f_cancelRow(3);
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {
    if (ds_selling.getRowCount() == 0 && ds_partner.getRowCount() == 0 && ds_buying.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Freight Information"]);
        return;
    }
    // invoice Check
    await scwin.f_invoiceCheck();

    if (scwin.invoiceCheck == "1") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
        return;
    }

    if (await $c.win.confirm($c.data.getMessage(E_MSG_CM_CRM_004))) {
        // 전체 Delete 플래그 설정 후 서버 삭제
        for (var i = 0; i < ds_selling.getRowCount(); i++) {
            ds_selling.deleteRow(i);
        }
        for (i = 0; i < ds_partner.getRowCount(); i++) {
            ds_partner.deleteRow(i);
        }
        for (i = 0; i < ds_buying.getRowCount(); i++) {
            ds_buying.deleteRow(i);
        }
        await $c.sbm.execute(sbm_delete);
    }
};

