    //         ds = ds_buying;
    //         certiCol = "pchsCertiNo";
    //         needConfirmBlock = true;
    //         break;
    //     default:
    //         return;
    // }

    // if (ds.getRowCount() == 0) return;


    // const cur = ds.getRowPosition();
    // const rc = ds.getRowCount();

    // // 삭제 대상 수집(중복 제거) → 내림차순
    // const targetsMap = {};
    // for (let r = 0; r < rc; r++) {
    //     const chk = ds.getCellData(r, "chk"); // getValue → getCellData
    //     if (chk == "T" || r == cur) targetsMap[r] = true;
    // }

    // const targets = Object.keys(targetsMap)
    //     .map((x) => parseInt(x, 10))
    //     .sort((a, b) => b - a);

    // for (let i = 0; i < targets.length; i++) {
    //     const row = targets[i];

    //     // 1) Invoice 존재 시 삭제 금지
    //     const certiNo = ds.getCellData(row, certiCol);
    //     if (certiNo) {
    //         await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, Array("Invoice No", "delete"));
    //         return;
    //     }

    //     // 2) Partner/Buying: 확정이면 삭제 금지
    //     if (needConfirmBlock) {
    //         const dcsn = ds.getCellData(row, "dcsnClsCd");
    //         if (dcsn == "확정") {
    //             await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["확정", "delete"]);
    //             return;
    //         }
    //     }

    //     ds.deleteRow(row);
    // }

    var tmp = ""; // 행을 삭제할 ds 저장해 둘 곳.
    var tmpRowPosition = -1;
    var removeR = [];
    var deleteR = [];
    var addRowState = "";

    switch (disGubun) {
        case 1:  	//Selling
            tmp = ds_selling;
            tmpRowPosition = tmp.getRowPosition();

            for (var i = 0; i < tmp.getRowCount(); i++) {
                var rJson = tmp.getRowJSON(i);
                addRowState = tmp.getRowStatus(i);

                if (rJson.chk == "T" || i == tmpRowPosition) {
                    if (rJson.certiNo == "") {
                        if (addRowState == "C") {
                            removeR.push(i);

                        } else {
                            deleteR.push(i);
                        }
                    } else {
                        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);  // @은(는) @할 수 없습니다.
                        return;
                    }
                }
            }

            break;

        case 2:  	// Partner
            tmp = ds_partner;
            tmpRowPosition = tmp.getRowPosition();

            for (var i = 0; i < tmp.getRowCount(); i++) {
                var rJson = tmp.getRowJSON(i);
                addRowState = tmp.getRowStatus(i);

                if (rJson.chk == "T" || i == tmpRowPosition) {
                    if (rJson.certiNo == "") {
                        if (rJson.dcsnClsCd == "확정") {
                            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["확정", "delete"]);  // @은(는) @할 수 없습니다.
                            return;
                        } else {
                            if (addRowState == "C") {
                                removeR.push(i);
                            } else {
                                deleteR.push(i);
                            }
                        }
                    } else {
                        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);  // @은(는) @할 수 없습니다.
                        return;
                    }
                }
            }

            break;

        case 3:  	// Buying
            tmp = ds_buying;
            tmpRowPosition = tmp.getRowPosition();
            for (var i = 0; i < tmp.getRowCount(); i++) {
                var rJson = tmp.getRowJSON(i);
                addRowState = tmp.getRowStatus(i);

                if (rJson.chk == "T" || i == tmpRowPosition) {
                    if (rJson.pchsCertiNo == "") {
                        if (rJson.dcsnClsCd == "확정") {
                            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["확정", "delete"]);  // @은(는) @할 수 없습니다.
                            return;
                        } else {
                            if (addRowState == "C") {
                                removeR.push(i);
                            } else {
                                deleteR.push(i);
                            }
                        }
                    } else {
                        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);  // @은(는) @할 수 없습니다.
                        return;
                    }
                }
            }

            break;

        default:
            break;
    }
    if (removeR.length != 0) {
        tmp.removeRows(removeR);
    }

    if (deleteR.length != 0) {
        tmp.deleteRows(deleteR)
    }
};


//-------------------------------------------------------------------------
// 행 전체삭제 (disGubun: 1 Selling, 2 Partner, 3 Buying)
// - "현재행"의 certiNo/pchsCertiNo 존재 시 전체삭제 불가
// - 그 외 모든 행을 뒤에서부터 삭제
// - Partner/Buying: dcsnClsCd == "확정" 삭제 불가
//-------------------------------------------------------------------------
scwin.f_deleteAllRow = async function (disGubun) {
    var ds;
    switch (disGubun) {
        case 1:  	//Selling
            if (ds_selling.getCellData(ds_selling.getRowPosition() || 0, "certiNo") == "") {
                ds = ds_selling;
            } else {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);  // @은(는) @할 수 없습니다.
                return;
            }
            break;

        case 2:  	// Partner
            if (ds_partner.getCellData(ds_partner.getRowPosition() || 0, "certiNo") == "") {
                ds = ds_partner;
            } else {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);  // @은(는) @할 수 없습니다.
                return;
            }
            break;

        case 3:  	// Buying
            if (ds_buying.getCellData(ds_buying.getRowPosition() || 0, "pchsCertiNo") == "") {
                ds = ds_buying;
            } else {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);  // @은(는) @할 수 없습니다.
                return;
            }
            break;

        default:
            break;
    }

    for (let i = ds.getRowCount() - 1; i >= 0; i--) {
        ds.setRowPosition(i);
        await scwin.f_deleteRow(disGubun);

    }
};

//-------------------------------------------------------------------------
// 행 취소(원본 로직 유지)
// - 첫 행 tabIndex가 각 구분의 기본 탭이면 removeAll
// - 아니면 undoAll
//-------------------------------------------------------------------------
scwin.f_cancelRow = async function (disGubun) {
    var creatRow = [];
    switch (disGubun) {
        case 1:  	//Selling
            if (ds_selling.getCellData(0, "tabIndex") == "0") {
                ds_selling.setJSON([]);
            } else {
                ds_selling.undoAll();

                //tobe추가 : 행추가해서 생긴 행은 취소하면 화면에서 삭제됨.
                creatRow = ds_selling.getRowIndexByStatus("C");
                ds_selling.removeRows(creatRow);

            }
            break;
        case 2:  	// Partner
            if (ds_partner.getCellData(0, "tabIndex") == "1") {
                ds_partner.setJSON([]);
            } else {
                ds_partner.undoAll();

                //tobe추가 : 행추가해서 생긴 행은 취소하면 화면에서 삭제됨.
                creatRow = ds_partner.getRowIndexByStatus("C");
                ds_partner.removeRows(creatRow);

            }
            break;
        case 3:  	// Buying
            if (ds_buying.getCellData(0, "tabIndex") == "2") {
                ds_buying.setJSON([]);
            } else {
                ds_buying.undoAll();

                //tobe추가 : 행추가해서 생긴 행은 취소하면 화면에서 삭제됨.
                creatRow = ds_buying.getRowIndexByStatus("C");
                ds_buying.removeRows(creatRow);

            }
            break;

        default:
            break;
    }
};


