//-------------------------------------------------------------------------
// function name : f_validate
// function desc : validation (WebSquare direct API + DataList getCellData)
//-------------------------------------------------------------------------
scwin.f_validate = async function () {

    // VALIDATE (validExp 가 yes일때 check)
    if (!await $c.gus.cfValidate([ed_hhcurdt, ed_hhetd, gr_selling, gr_partner, gr_buying])) {
        return false;
    }

    // ===========
    // Header 필수값
    // ===========
    if (ed_hhcur.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]);
        ed_hhcur.focus();
        return false;
    }

    if (cnd_ed_hhblno.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House B/L"]);
        cnd_ed_hhblno.focus();
        return false;
    }

    if (ed_hhetd.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["ETD"]);
        ed_hhetd.focus();
        return false;
    }

    // ===========
    // Container Type 체크 (DataList -> getCellData 사용)
    // ===========
    function hasContainerType(code) {
        if (code == "") return true;
        var idx = ds_containerType.getMatchedIndex("code", code);
        if (idx < 0) idx = ds_containerType.getMatchedIndex("cd", code);
        return idx >= 0;
    }

    if (ed_hhcnt1type.getValue() != "" && !hasContainerType(ed_hhcnt1type.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]);
        ed_hhcnt1type.focus();
        return false;
    }
    if (ed_hhcnt2type.getValue() != "" && !hasContainerType(ed_hhcnt2type.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]);
        ed_hhcnt2type.focus();
        return false;
    }
    if (ed_hhcnt3type.getValue() != "" && !hasContainerType(ed_hhcnt3type.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]);
        ed_hhcnt3type.focus();
        return false;
    }
    if (ed_hhcnt4type.getValue() != "" && !hasContainerType(ed_hhcnt4type.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]);
        ed_hhcnt4type.focus();
        return false;
    }

    // ===========
    // SELLING 필수 체크 (DataList: getCellData)
    // ===========
    for (var i = 0; i < ds_selling.getRowCount(); i++) {
        if (ds_selling.getCellData(i, "bilgClntNm") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer Name"]);
            gr_selling.focus();
            gr_selling.setFocusedCell(i, "bilgClntNm", true);
            return false;
        }
    }

    for (var i = 0; i < ds_selling.getRowCount(); i++) {
        if (ds_selling.getCellData(i, "bilgClntNo") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer"]);
            gr_selling.focus();
            gr_selling.setFocusedCell(i, "bilgClntNo", true);
            return false;
        }
    }

    for (var i = 0; i < ds_selling.getRowCount(); i++) {
        if (ds_selling.getCellData(i, "fareEngCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["F/Code"]);
            gr_selling.focus();
            gr_selling.setFocusedCell(i, "fareEngCd", true);
            return false;
        }
    }

    for (var i = 0; i < ds_selling.getRowCount(); i++) {
        if (ds_selling.getCellData(i, "crcCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]);
            gr_selling.focus();
            gr_selling.setFocusedCell(i, "crcCd", true);
            return false;
        }
    }

    for (var i = 0; i < ds_selling.getRowCount(); i++) {
        if (ds_selling.getCellData(i, "fareUnit") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Unit"]);
            gr_selling.focus();
            gr_selling.setFocusedCell(i, "fareUnit", true);
            return false;
        }
    }

    // ===========
    // PARTNER 필수 체크 (DataList: getCellData)
    // ===========

    for (var i = 0; i < ds_partner.getRowCount(); i++) {
        if (ds_partner.getCellData(i, "bilgClntNo") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer"]);
            gr_partner.focus();
            gr_partner.setFocusedCell(i, "bilgClntNo", true);
            return false;
        }
    }

    for (var i = 0; i < ds_partner.getRowCount(); i++) {
        if (ds_partner.getCellData(i, "bilgClntNm") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer Name"]);
            gr_partner.focus();
            gr_partner.setFocusedCell(i, "bilgClntNm", true);
            return false;
        }
    }

    for (var i = 0; i < ds_partner.getRowCount(); i++) {
        if (ds_partner.getCellData(i, "fareEngCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["F/Code"]);
            gr_partner.focus();
            gr_partner.setFocusedCell(i, "fareEngCd", true);
            return false;
        }
    }

    for (var i = 0; i < ds_partner.getRowCount(); i++) {
        if (ds_partner.getCellData(i, "drcrCls") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["D/C"]);
            gr_partner.focus();
            gr_partner.setFocusedCell(i, "drcrCls", true);
            return false;
        }
    }

    for (var i = 0; i < ds_partner.getRowCount(); i++) {
        if (ds_partner.getCellData(i, "crcCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]);
            gr_partner.focus();
            gr_partner.setFocusedCell(i, "crcCd", true);
            return false;
        }
    }

    for (var i = 0; i < ds_partner.getRowCount(); i++) {
        if (ds_partner.getCellData(i, "fareUnit") == "") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["Unit"]);
            gr_partner.focus();
            gr_partner.setFocusedCell(i, "fareUnit", true);
            return false;
        }
    }

    // ===========
    // BUYING 필수 체크 (DataList: getCellData)
    // ===========
    for (var b = 0; b < ds_buying.getRowCount(); b++) {
        if (ds_buying.getCellData(b, "pchsTyp") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Type"]);
            gr_buying.focus();
            gr_buying.setFocusedCell(b, "pchsTyp", true);
            return false;
        }


        if (ds_buying.getCellData(b, "pchsClntNo") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer"]);
            gr_buying.focus();
            gr_buying.setFocusedCell(b, "pchsClntNo", true);
            return false;
        }

        if (ds_buying.getCellData(b, "pchsClntNm") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer Name"]);
            gr_buying.focus();
            gr_buying.setFocusedCell(b, "pchsClntNm", true);
            return false;
        }

        if (ds_buying.getCellData(b, "fareEngCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["F/Code"]);
            gr_buying.focus();
            gr_buying.setFocusedCell(b, "fareEngCd", true);
            return false;
        }

        if (ds_buying.getCellData(b, "crcCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]);
            gr_buying.focus();
            gr_buying.setFocusedCell(b, "crcCd", true);
            return false;
        }

        if (ds_buying.getCellData(b, "fareUnit") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Unit"]);
            gr_buying.focus();
            gr_buying.setFocusedCell(b, "fareUnit", true);
            return false;
        }

        // Buying Inner Dept
        if (ds_buying.getCellData(b, "pchsTyp") == "3" && ds_buying.getCellData(b, "sellDeptCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Inner Department"]);
            gr_buying.focus();
            gr_buying.setFocusedCell(b, "sellDeptCd", true);
            return false;
        }
    }

    // ===========
    // SELLING 상세 체크 (VAT/금액0/내부거래)
    // ===========
    for (var i = 0; i < ds_selling.getRowCount(); i++) {

        var vatYn = ds_selling.getCellData(i, "vatYn");
        var vatAmt = Number(ds_selling.getCellData(i, "vatAmt") || 0);
        var sellAmt = Number(ds_selling.getCellData(i, "sellAmt") || 0);

        if (vatYn == 0) {
            if (vatAmt > 0) {
                await $c.win.alert("영세코드와 부가세 금액은 함께 입력될 수 없습니다. \nSelling List " + (i + 1) + "번째 데이터를 확인하세요.");
                gr_selling.focus();
                gr_selling.setFocusedCell(i, "vatAmt", true);
                return false;
            }
        }

        if (vatYn == 1) {
            if (Math.abs(Math.round(sellAmt * 0.1) - vatAmt) > 1) {
                await $c.win.alert("VAT 금액은 Amount(W)금액의 10%입니다.\nSelling List " + (i + 1) + "번째 VAT 금액을 확인하세요.");
                gr_selling.focus();
                gr_selling.setFocusedCell(i, "vatAmt", true);
                return false;
            }
        }

        if (sellAmt == 0) {
            await $c.win.alert("Amount(W) 금액이 0입니다. \nSelling List " + (i + 1) + "번째 데이터를 확인하세요.");
            gr_selling.focus();
            gr_selling.setFocusedCell(i, "sellAmt", true);
            return false;
        }

        // 삭제 시 내부거래 체크
        if (ds_selling.getRowStatus(i) == "D") {
            await scwin.f_postDtChk(
                ds_selling.getCellData(i, "odrNo"),
                ds_selling.getCellData(i, "sellSeq"),
                ds_selling.getCellData(i, "kcomcd"),
                ds_selling.getCellData(i, "seaAirCls"),
                ds_selling.getCellData(i, "blNo"),
                ds_selling.getCellData(i, "mhno")
            );

            var isPostDt = ds_PostDtDataSet.getCellData(0, "col1") || "";
            if (isPostDt != "") {
                await $c.win.alert("내부거래 확정 건 입니다. \nSelling List " + (i + 1) + "번째 데이터를 확인하세요.");
                return false;
            }
        }
    }

    // ===========
    // BUYING 상세 체크 (VAT/금액0/내부거래)
    // ===========
    for (var b = 0; b < ds_buying.getRowCount(); b++) {

        var vatYn = ds_buying.getCellData(b, "vatYn");
        var vat = Number(ds_buying.getCellData(b, "vat") || 0); // 원본: vat
        var pchsAmt = Number(ds_buying.getCellData(b, "pchsAmt") || 0);

        if (vatYn == 0) {
            if (vat > 0) {
                await $c.win.alert("영세코드와 부가세 금액은 함께 입력될 수 없습니다. \nBuying List " + (b + 1) + "번째 데이터를 확인하세요.");
                gr_buying.focus();
                gr_buying.setFocusedCell(b, "vatAmt", true);
                return false;
            }
        }

        if (pchsAmt == 0) {
            await $c.win.alert("Amount(W) 금액이 0입니다. \nBuying List " + (b + 1) + "번째 데이터를 확인하세요.");
            gr_buying.focus();
            gr_buying.setFocusedCell(b, "pchsAmt", true);
            return false;
        }

        // 삭제 시 내부거래 체크
        if (ds_buying.getRowStatus(b) == "D") {
            await scwin.f_postDtChk(
                ds_buying.getCellData(b, "odrNo"),
                ds_buying.getCellData(b, "pchsSeq"),
                ds_buying.getCellData(b, "kcomcd"),
                ds_buying.getCellData(b, "seaAirCls"),
                ds_buying.getCellData(b, "blNo"),
                ds_buying.getCellData(b, "mhno")
            );

            var isPostDt2 = ds_PostDtDataSet.getCellData(0, "col1") || "";
            if (isPostDt2 != "") {
                await $c.win.alert("내부거래 확정 건 입니다. \nbuying List " + (b + 1) + "번째 데이터를 확인하세요.");
                return false;
            }
        }
    }

    // ===========
    // PARTNER 상세 체크 (금액0/내부거래)
    // ===========
    for (var i = 0; i < ds_partner.getRowCount(); i++) {

        var sellAmt = Number(ds_partner.getCellData(i, "sellAmt") || 0);
        if (sellAmt == 0) {
            await $c.win.alert("Amount(W) 금액이 0입니다. \nPartner List " + (i + 1) + "번째 데이터를 확인하세요.");
            gr_partner.focus();
            gr_partner.setFocusedCell(i, "sellAmt", true);
            return false;
        }

        // 삭제 시 내부거래 체크
        if (ds_partner.getRowStatus(i) == "D") {
            await scwin.f_postDtChk(
                ds_partner.getCellData(i, "odrNo"),
                ds_partner.getCellData(i, "sellSeq"),
                ds_partner.getCellData(i, "kcomcd"),
                ds_partner.getCellData(i, "seaAirCls"),
                ds_partner.getCellData(i, "blNo"),
                ds_partner.getCellData(i, "mhno")
            );

            var isPostDt3 = ds_PostDtDataSet.getCellData(0, "col1") || "";
            if (isPostDt3 != "") {
                await $c.win.alert("내부거래 확정 건 입니다. \nPartner List " + (i + 1) + "번째 데이터를 확인하세요.");
                return false;
            }
        }
    }

    // ilcommon.js - Freight Name Validation Check
    if (!await scwin.cf_freightNameValidation(ds_selling, ds_partner, ds_buying)) {
        return false;
    }

    return true;
};

/**
 * @type   : function
 * @access : public
 * @desc   : Freight Name이 바이트 기준으로 45자를 초과하지 않도록 check
 * @author : 이연희
 */
scwin.cf_freightNameValidation = async function (ds1, ds2, ds3) { // Selling, Partner, Buying (체크안할경우 null)
    const LIMIT = 45;

    const getByte = function (str) {
        if (!str) return 0;
        return new Blob([str], { type: "text/plain;charset=UTF-8" }).size;
    };

    const check = async function (ds, listName, certiCol) {
        if (!ds) return true;

        const rc = ds.getRowCount();
        for (let i = 0; i < rc; i++) {
            const certiNo = String(ds.getCellData(i, certiCol) || "").trim();
            const fareEngNm = String(ds.getCellData(i, "fareEngNm") || "");
            const bytes = getByte(fareEngNm);

            if (certiNo === "" && bytes > LIMIT) {
                await $c.win.alert(
                    "Freight Name은 45바이트 초과로 입력할 수 없습니다.\n" +
                    listName + " List를 확인하세요.\n" +
                    (i + 1) + "번째 행 입력 바이트 수: " + bytes
                );
                return false;
            }
        }
        return true;
    };

    // ds.isUpdated 대체: 변경건 존재 여부로 체크(없으면 전체검사)
    if (!(await check(ds1, "Selling", "certiNo"))) return false;
    if (!(await check(ds2, "Partner", "certiNo"))) return false;
    if (!(await check(ds3, "Buying", "pchsCertiNo"))) return false;

    return true;
};



