                , null				// POP-UP뛰을때	원도우의	사용자 정의	폭
                , null				// POP-UP뛰을때	우도우의	사용자 정의	높이
                , null				// 윈도우 위치 Y좌표
                , null				// 윈도우 위치 X좌표
                , null				// 중복체크여부	("F")
                , pAllSearchTF		// 전체검색허용여부	("F")
                , "Type,Code,Name"	// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                , 'F'				// Data	건수가 0 일때 Window를 뛰우지 않음 리턴	: "N/A"
            );
            break;
        case "ContainerType4":
            udc_hhcnt4type.setSelectId("retriveContainerTypeCodeInfo");
            await udc_hhcnt4type.ilCommonPopUp(function (rtnList) {
                $c.gus.cfSetReturnValue(rtnList, ed_hhcnt4type, "");
            }
                , ed_hhcnt4type.getValue().trim()	 //코드
                , '' 	 //코드명
                , pWinCloseTF		// 결과가 1건 일때	원도우를	AutoClose 여부	(T:Close,F:Opened)
                , '2'				// 검색	결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 -	default	(2)
                , "Code, Name"		// Title순서
                , '80,230'			// 보여주는	각 컬럼들의	폭
                , "3,4,5,6,7,8,9,10"	// 컬럼중에서 숨기는	컬럼 지정
                , null				// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null				// POP-UP뛰을때	원도우의	사용자 정의	폭
                , null				// POP-UP뛰을때	우도우의	사용자 정의	높이
                , null				// 윈도우 위치 Y좌표
                , null				// 윈도우 위치 X좌표
                , null				// 중복체크여부	("F")
                , pAllSearchTF		// 전체검색허용여부	("F")
                , "Type,Code,Name"	// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                , 'F'				// Data	건수가 0 일때 Window를 뛰우지 않음 리턴	: "N/A"
            );
            break;
    }
};

//---------------------------------------------------------
// 공통 콜백: Code + Name 세팅 (Loading/Discharge용)
//---------------------------------------------------------
scwin._callbackCommonCodeName = function (rtnList) {

    if (!rtnList || rtnList == "N/A") return;

    var code = "";
    var name = "";

    if (Array.isArray(rtnList)) {
        code = rtnList[0] || "";
        name = rtnList[1] || "";
    } else if (rtnList.list && Array.isArray(rtnList.list)) {
        code = rtnList.list[0] || "";
        name = rtnList.list[1] || "";
    } else {
        code = rtnList.code || rtnList[0] || "";
        name = rtnList.name || rtnList[1] || "";
    }

    if (scwin._popupCodeComp) scwin._popupCodeComp.setValue(code);
    if (scwin._popupNameComp) scwin._popupNameComp.setValue(name);

    //if(scwin._popupCodeComp) scwin._popupCodeComp.focus();
};

//---------------------------------------------------------
// 공통 콜백: Code만 세팅 (ContainerType용)
//---------------------------------------------------------
scwin._callbackCommonCodeOnly = function (rtnList) {

    if (!rtnList || rtnList == "N/A") return;

    var code = "";

    if (Array.isArray(rtnList)) {
        code = rtnList[0] || "";
    } else if (rtnList.list && Array.isArray(rtnList.list)) {
        code = rtnList.list[0] || "";
    } else {
        code = rtnList.code || rtnList[0] || "";
    }

    if (code == "") return;

    if (scwin._popupCodeComp) {
        scwin._popupCodeComp.setValue(code);
        //scwin._popupCodeComp.focus();
    }
};

//-------------------------------------------------------------------------
// 화면이동 (WebSquare)
//-------------------------------------------------------------------------
scwin.f_openPgm = function (name) {

    // 공통 파라미터(Partner/Invoice/Profit/PaymentINV에서 공통)
    var commonParam = {
        kcomcd: scwin.hd_kcomcd || "",                                   // kcomcd
        seaair: "S",                                                     // sea:S, air:A
        iogb: scwin.hd_hhio,                      // out:O, in:I
        blno: (cnd_ed_hhblno ? cnd_ed_hhblno.getValue() : ""),          // house blno
        mblno: "",                                                      // master blno
        mhno: (cnd_lc_mhno ? cnd_lc_mhno.getValue() : "")               // mhno
    };

    // 메뉴 오픈 헬퍼
    function openMenu(title, path, menuId, param) {
        $c.win.openMenu(title, path, menuId, param || {}, { openAction: "exist" });
    }

    if (name == "Partner") {
        var path = "/ui/il/acc/acpar/ac_104_01_01b.xml";
        openMenu("Partner Statement", path, "ac_104_01_01b.xml", commonParam);

    } else if (name == "Invoice") {
        var path = "/ui/il/acc/acinv/ac_101_01_01b.xml";
        openMenu("Invoice", path, "ac_101_01_01b.xml", commonParam);

    } else if (name == "Profit") {
        var path = "/ui/il/pfm/pfbs/pe_101_01_01b.xml";
        openMenu("Booking Sheet", path, "pe_101_01_01b.xml", commonParam);

    } else if (name == "HouseBLFind") {
        // 이 케이스는 hhio만 사용하던 원본 그대로 반영
        var path = "/ui/il/seaout/sobl/se_105_01_02b.xml";
        var param = {
            hhio: scwin.hd_hhio
        };
        openMenu("House B/L Search", path, "se_105_01_02b.xml", param);

    } else if (name == "HouseBLHeader") {
        // 원본: linkcheck=2 + kcomcd + blno + mhno
        var path = "/ui/il/seaout/sobl/se_105_01_01b.xml";
        var param = {
            linkcheck: "2",
            kcomcd: scwin.hd_kcomcd || "",
            blno: (cnd_ed_hhblno ? cnd_ed_hhblno.getValue() : ""),
            mhno: (cnd_lc_mhno ? cnd_lc_mhno.getValue() : "")
        };
        openMenu("Export House B/L", path, "se_105_01_01b.xml", param);

    } else if (name == "paymentINV") {
        // 원본: kcomcd, seaair, iogb, blno, mhno
        var path = "/ui/il/acc/acpay/ac_106_01_01b.xml";
        var param = {
            kcomcd: scwin.hd_kcomcd || "",
            seaair: "S",
            iogb: scwin.hd_hhio,
            blno: (cnd_ed_hhblno ? cnd_ed_hhblno.getValue() : ""),
            mhno: (cnd_lc_mhno ? cnd_lc_mhno.getValue() : "")
        };
        openMenu("Payment Invoice", path, "ac_106_01_01b.xml", param);
    }
};

//-------------------------------------------------------------------------
// Refactored 조회 유틸/함수들
//-------------------------------------------------------------------------

// 공통 코드조회 (param1~4)
// - sysCd 생략 시 "ilCommonEBC" 기본
scwin.f_commCode = async function (sysCd, queryId, param1, param2, param3, param4) {
    // sysCd 생략 호출 허용: f_commCode("queryId", p1, p2 ...)
    if (queryId === undefined) {
        queryId = sysCd;
        sysCd = "ilCommonEBC";
        param4 = param3;
        param3 = param2;
        param2 = param1;
        param1 = "";
    }

    var params = {
        sysCd: sysCd || "ilCommonEBC",
        queryId: queryId || "",
        param1: (param1 == undefined ? "" : param1),
        param2: (param2 == undefined ? "" : param2),
        param3: (param3 == undefined ? "" : param3),
        param4: (param4 == undefined ? "" : param4)
    };
    dma_combo.setEmptyValue();
    dma_combo.setJSON(params);
    $c.sbm.execute(sbm_combo);
};

//-------------------------------------------------------------------------
// sbm_combo onsubmitdone (정리/중복 제거 버전)
// - rs: 실제 응답 DataList명으로 교체 필요
//-------------------------------------------------------------------------
//-------------------------------------------------------------------------
// sbm_combo onsubmitdone (WebSquare)
//-------------------------------------------------------------------------
scwin._exRateTarget = "";
scwin.sbm_combo_onsubmitdone = async function (e) {

    //var rs = ds_combo; // ✅ 실제 응답 DataList로 변경

    //==========================
    // 1) MHNO(HH) 처리
    //==========================
    if (scwin._comboTarget == "HMHNO1") {
        ds_hmhno.setJSON(e.responseJSON.GAUCE);

        //  for=ds_hmhno event=OnLoadCompleted(rowcnt)
        if (ds_hmhno.getRowCount() == 0) {
            if (scwin.statusFlag != "C") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["House No"]); // ✅ 이제 에러 안남
            }

            var r0 = ds_hmhno.insertRow(0);
            ds_hmhno.setCellData(r0, "code", "NONE");
            ds_hmhno.setCellData(r0, "name", "NONE");

            if (cnd_lc_mhno && cnd_lc_mhno.setSelectedIndex) {
                cnd_lc_mhno.setSelectedIndex(0);
            } else if (cnd_lc_mhno && cnd_lc_mhno.setValue) {
                cnd_lc_mhno.setValue("NONE");
            }
        }

        if (scwin.mhnoFlag == "1") {
            scwin.f_Retrieve();
            scwin.mhnoFlag = "0";
        }
        scwin._comboTarget = "";
        return;
    }

    //==========================
    if (scwin._comboTarget == "HMHNO2") {
        ds_hmhno2.setJSON(e.responseJSON.GAUCE);
        // 비어있으면 NONE 세팅
        if (ds_hmhno2.getRowCount() == 0) {
            if (scwin.statusFlag != "C") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["House No"]); // ✅ 이제 에러 안남
            }

            var r0 = ds_hmhno2.insertRow(0);
            ds_hmhno2.setCellData(r0, "code", "NONE");
            ds_hmhno2.setCellData(r0, "name", "NONE");

            if (srch_ed_hhblno && srch_ed_hhblno.setSelectedIndex) {
                srch_ed_hhblno.setSelectedIndex(0);
            } else if (srch_ed_hhblno && srch_ed_hhblno.setValue) {
                srch_ed_hhblno.setValue("NONE");
            }
        }
        scwin._comboTarget = "";
        return;
    }

    //==========================
    // 1) INVOICE 처리
    //==========================
    if (scwin._comboTarget == "INVOICE") {
        ds_invoiceCheck.setJSON(e.responseJSON.GAUCE);
        if (ds_invoiceCheck.getCellData(ds_invoiceCheck.getRowPosition(), "code") != "0") {
            scwin.invoiceCheck = "1";
        }
        scwin._comboTarget = "";
    }

    //==========================
    // 1) SELLING_UNIT 처리
    //==========================
    if (scwin._comboTarget == "SELLING_UNIT") {
        ds_sellingUnit.setJSON(e.responseJSON.GAUCE);
        scwin._comboTarget = "";
    }

    //==========================
    // 1) INVOICE 처리
    //==========================
    if (scwin._comboTarget == "PARTNER_UNIT") {
        ds_partnerUnit.setJSON(e.responseJSON.GAUCE);
        scwin._comboTarget = "";
    }

    //==========================
    // 1) INVOICE 처리
    //==========================
    if (scwin._comboTarget == "BUYING_UNIT") {
        ds_buyingUnit.setJSON(e.responseJSON.GAUCE);
        scwin._comboTarget = "";
    }

    //tobe 추가
    if (scwin._comboTarget == 'CURRENCY') {
        ds_currencyCode.setJSON(e.responseJSON.GAUCE);
        scwin._comboTarget = "";
    }

    //tobe 추가
    if (scwin._comboTarget == "PARTER_CODE") {
        ds_ParterCode.setJSON(e.responseJSON.GAUCE);
        scwin._comboTarget = "";
    }

    //==========================
    // 2) exRateTarget 처리 (HOUSE/SELLING/BUYING/PARTNER)
    //==========================
    if (scwin._exRateTarget) {

        ds_exHouseRate.setJSON(e.responseJSON.GAUCE);

        var code2 = String(ds_exHouseRate.getCellData(0, "code") || "").trim();
        var name2 = String(ds_exHouseRate.getCellData(0, "name") || "").trim();

        if (scwin._exRateTarget == "HOUSE") {
            if (ed_hhexrate) ed_hhexrate.setValue(code2);
            if (ed_hhuexrate) ed_hhuexrate.setValue(name2);

            if (code2 == "" && scwin._exRateCur != "KRW") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Ex-Rate"]);
                scwin.exRateCheck = "1";
            } else {
                scwin.exRateCheck = "2";
                scwin.exRate1 = code2;
                scwin.exRate2 = name2;
                scwin.crc = scwin._exRateCur;
            }

        } else if (scwin._exRateTarget == "SELLING") {

            ds_selling.setCellData(scwin._exRateRow, "exRate", code2);
            if (code2 == "" && scwin._exRateCur != "KRW") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Ex-Rate"]);
            }

        } else if (scwin._exRateTarget == "BUYING") {

            ds_buying.setCellData(scwin._exRateRow, "exRate", code2);
            if (code2 == "" && scwin._exRateCur != "KRW") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Ex-Rate"]);
            }

        } else if (scwin._exRateTarget == "PARTNER") {

            ds_partner.setCellData(scwin._exRateRow, "exRate", code2);
            if (code2 == "" && scwin._exRateCur != "KRW") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Ex-Rate"]);
            }
        }

        scwin._exRateTarget = "";
        scwin._exRateRow = -1;
        scwin._exRateCur = "";
    }


};

