//-------------------------------------------------------------------------
// ExRate Grid 공통 (Selling/Buying/Partner)
//-------------------------------------------------------------------------
scwin.f_loadExRateGrid = function (ds, target) {

    if (!ds) return;

    var rp = ds.getRowPosition();

    //tobe추가 : 그리드 안에서 popup 호출 후, 다른 셀 클릭시, poupcallback에서 poup호출 한 row가 아닌 클릭한 row값이 들어와서 추가.
    if (scwin.row != rp && !$c.gus.cfIsNull(scwin.row)) rp = scwin.row;

    if (rp < 0) return;

    var houseCur = ed_hhcur ? String(ed_hhcur.getValue() || "").trim() : "";
    var rowCur = String(ds.getCellData(rp, "crcCd") || "").trim();

    // house currency == row currency → house 환율 복사
    if (houseCur != "" && houseCur == rowCur) {
        ds.setCellData(rp, "exRate", ed_hhexrate ? ed_hhexrate.getValue() : "");
        return;
    }

    // 이미 환율이 있으면 조회 불필요
    var exRate = String(ds.getCellData(rp, "exRate") || "").trim();
    if (exRate != "" && exRate != "0") return;

    var param1 = rowCur;
    var param2 = ed_hhcurdt ? String(ed_hhcurdt.getValue() || "").trim() : "";
    var param3 = lc_hhexgb ? String(lc_hhexgb.getValue() || "").trim() : "";

    scwin._exRateTarget = target; // "SELLING" | "BUYING" | "PARTNER"
    scwin._exRateRow = rp;
    scwin._exRateCur = param1;

    scwin.f_commCode("ilCommonEBC", "retrieveExRate", param1, param2, param3);
};

scwin.f_ExRateSellingGridLoading = function () {
    scwin.f_loadExRateGrid(ds_selling, "SELLING");
};

scwin.f_ExRateBuyingGridLoading = function () {
    scwin.f_loadExRateGrid(ds_buying, "BUYING");
};

scwin.f_ExRatePartnerGridLoading = function () {
    scwin.f_loadExRateGrid(ds_partner, "PARTNER");
};


//-------------------------------------------------------------------------
// 컨테이너 타입/수량 기반 param1~4 만들기 공통
//-------------------------------------------------------------------------
scwin._getCntParams = function () {

    var cnt = ["0", "0", "0", "0"];
    var typeComp = [ed_hhcnt1type, ed_hhcnt2type, ed_hhcnt3type, ed_hhcnt4type];
    var qtyComp = [ed_hhcnt1, ed_hhcnt2, ed_hhcnt3, ed_hhcnt4];

    for (var i = 0; i < 4; i++) {
        var t = typeComp[i] ? String(typeComp[i].getValue() || "").trim() : "";
        var q = qtyComp[i] ? String(qtyComp[i].getValue() || "").trim() : "";

        if (t != "" && q != "" && q != "0") {
            cnt[i] = t;
        }
    }
    return cnt; // [cnt1,cnt2,cnt3,cnt4]
};


