scwin.f_Currency_Unit = function (curr) {
    return (curr == "JPY" || curr == "ITL" || curr == "IDR" || curr == "ESP") ? 100 : 1;
};

//-------------------------------------------------------------------------
// Amount(원화) -- Selling/Partner/Buying
//-------------------------------------------------------------------------
scwin.f_sellingAmt = function (row) {
    var r = row;

    if (ds_selling.getCellData(r, "crcCd") == "KRW") {
        var amt = (Number(ds_selling.getCellData(r, "chgWt")) || 0) * (Number(ds_selling.getCellData(r, "sellUpr")) || 0);
        ds_selling.setCellData(r, "sellAmt", Math.round(amt));
    } else {
        var unit = scwin.f_Currency_Unit(ds_selling.getCellData(r, "crcCd"));
        var amt = (Number(ds_selling.getCellData(r, "sellAmtFcrc")) || 0) * (Number(ds_selling.getCellData(r, "exRate")) || 0);
        ds_selling.setCellData(r, "sellAmt", Math.round(amt) / unit);
    }
};
scwin.f_partnerAmt = function (row) {
    var r = row;
    if (ds_partner.getCellData(r, "crcCd") == "KRW") {
        var amt = (Number(ds_partner.getCellData(r, "chgWt")) || 0) * (Number(ds_partner.getCellData(r, "sellUpr")) || 0);
        ds_partner.setCellData(r, "sellAmt", Math.round(amt));
    } else {
        var unit = scwin.f_Currency_Unit(ds_partner.getCellData(r, "crcCd"));
        var amt = (Number(ds_partner.getCellData(r, "sellAmtFcrc")) || 0) * (Number(ds_partner.getCellData(r, "exRate")) || 0);
        ds_partner.setCellData(r, "sellAmt", Math.round(amt) / unit);
    }
};
scwin.f_buyingAmt = function (row) {
    var r = row;
    if (ds_buying.getCellData(r, "crcCd") == "KRW") {
        var amt = (Number(ds_buying.getCellData(r, "chgWt")) || 0) * (Number(ds_buying.getCellData(r, "pchsUpr")) || 0);
        ds_buying.setCellData(r, "pchsAmt", Math.round(amt));
    } else {
        var unit = scwin.f_Currency_Unit(ds_buying.getCellData(r, "crcCd"));
        var amt = (Number(ds_buying.getCellData(r, "pchsAmtFcrc")) || 0) * (Number(ds_buying.getCellData(r, "exRate")) || 0);
        ds_buying.setCellData(r, "pchsAmt", Math.round(amt) / unit);
    }
};

