//-------------------------------------------------------------------------
// Selling/Partner/Buying Sum
//-------------------------------------------------------------------------
scwin.f_SellingSum = function () {
    var sumAmtF = 0, sumAmt = 0, sumVat = 0, sumUsd = 0, sumKrw = 0;
    for (var i = 0; i < ds_selling.getRowCount(); i++) {
        if (ds_selling.getRowStatus && ds_selling.getRowStatus(i) == "D") continue;
        sumAmtF += Number(ds_selling.getCellData(i, "sellAmtFcrc")) || 0;
        sumAmt += Number(ds_selling.getCellData(i, "sellAmt")) || 0;
        sumVat += Number(ds_selling.getCellData(i, "vatAmt")) || 0;
        sumUsd += Number(ds_selling.getCellData(i, "usdAmt")) || 0;
        if (ds_selling.getCellData(i, "crcCd") == "KRW") {
            sumKrw += (Number(ds_selling.getCellData(i, "sellAmt")) || 0) + (Number(ds_selling.getCellData(i, "vatAmt")) || 0);
        }
    }
    if (ed_SellingSumAmount) ed_SellingSumAmount.setValue(sumAmtF);
    if (ed_SellingSumAmountW) ed_SellingSumAmountW.setValue(sumAmt);
    if (ed_SellingSumVat) ed_SellingSumVat.setValue(sumVat);
    if (ed_SellingAmountSum) ed_SellingAmountSum.setValue(sumAmt + sumVat);
};
scwin.f_PartnerSum = function () {

    var sumAmtF = 0, sumAmt = 0, sumUsd = 0, sumKrw = 0;
    for (var i = 0; i < ds_partner.getRowCount(); i++) {
        if (ds_partner.getRowStatus && ds_partner.getRowStatus(i) == "D") continue;
        sumAmtF += Number(ds_partner.getCellData(i, "sellAmtFcrc")) || 0;
        sumAmt += Number(ds_partner.getCellData(i, "sellAmt")) || 0;
        sumUsd += Number(ds_partner.getCellData(i, "usdAmt")) || 0;
        if (ds_partner.getCellData(i, "crcCd") == "KRW") {
            sumKrw += Number(ds_partner.getCellData(i, "sellAmt")) || 0;
            // vatAmt 합산은 원본에서 주석 처리되어 있었음
        }
    }

    if (ed_PartnerSumAmount) ed_PartnerSumAmount.setValue(sumAmtF);
    if (ed_PartnerSumAmountW) ed_PartnerSumAmountW.setValue(sumAmt);
};
scwin.f_BuyingSum = function () {
    var sumAmtF = 0, sumAmt = 0, sumVat = 0, sumUsd = 0, sumKrw = 0;
    for (var i = 0; i < ds_buying.getRowCount(); i++) {
        if (ds_buying.getRowStatus && ds_buying.getRowStatus(i) == "D") continue;
        sumAmtF += Number(ds_buying.getCellData(i, "pchsAmtFcrc")) || 0;
        sumAmt += Number(ds_buying.getCellData(i, "pchsAmt")) || 0;
        sumVat += Number(ds_buying.getCellData(i, "vat")) || 0;
        sumUsd += Number(ds_buying.getCellData(i, "usdAmt")) || 0;
        if (ds_buying.getCellData(i, "crcCd") == "KRW") {
            sumKrw += (Number(ds_buying.getCellData(i, "pchsAmt")) || 0) + (Number(ds_buying.getCellData(i, "vat")) || 0);
        }
    }
    if (ed_BuyingSumAmount) ed_BuyingSumAmount.setValue(sumAmtF);
    if (ed_BuyingSumAmountW) ed_BuyingSumAmountW.setValue(sumAmt);
    if (ed_BuyingSumVat) ed_BuyingSumVat.setValue(sumVat);
    if (ed_BuyingAmountSum) ed_BuyingAmountSum.setValue(sumAmt + sumVat);
};

