                ds_selling.setCellData(i, "sellItemCd", ds_buying.getCellData(i, "selpchItemCd"));
                ds_selling.setCellData(i, "crcCd", ds_buying.getCellData(i, "crcCd"));
                ds_selling.setCellData(i, "fareUnit", ds_buying.getCellData(i, "fareUnit"));
                ds_selling.setCellData(i, "chgWt", ds_buying.getCellData(i, "chgWt"));
                ds_selling.setCellData(i, "sellUpr", ds_buying.getCellData(i, "pchsUpr"));
                ds_selling.setCellData(i, "sellAmtFcrc", ds_buying.getCellData(i, "pchsAmtFcrc"));
                ds_selling.setCellData(i, "exRate", ds_buying.getCellData(i, "exRate"));
                ds_selling.setCellData(i, "sellAmt", ds_buying.getCellData(i, "pchsAmt"));
                ds_selling.setCellData(i, "vatAmt", ds_buying.getCellData(i, "vat"));
                ds_selling.setCellData(i, "usdAmt", ds_buying.getCellData(i, "usdAmt"));

                ds_selling.setCellData(i, "trfUpr", ds_buying.getCellData(i, "trfUpr"));
