//-------------------------------------------------------------------------
// 고객사 한화솔루션 매출운임계산 (WebSquare 변환 / 완성본)
// DOC, THC, OCF, WFG, AMS 코드별로 고정금액 기입 후 나머지 금액은 OTH로 기입
//
// 적용 규칙
// - alert            => await $c.win.alert(...)
// - cf*              => $c.gus.cf*(...)
// - GAUCE DataSet     => WebSquare DataList(getRowCount/getCellData/setCellData/insertRow)
// - 코드조회(DataID/Reset) 금지 => scwin.f_commCode + 로컬 f_commCodeAsync(조회 완료 후 ds_SellingCode 0행 사용)
//-------------------------------------------------------------------------
scwin.f_hanwhaFreight = async function () {

    // --- 공통코드조회 Promise 래퍼 (이 함수 내부 전용)
    function f_commCodeAsync(sysCd, queryId, p1, p2, p3, p4) {
        return new Promise(function (resolve, reject) {
            scwin._commCodeResolve = resolve;
            scwin._commCodeReject = reject;
            scwin._commCodeQueryId = queryId;
            scwin.f_commCode(sysCd, queryId, p1, p2, p3, p4);
        });
    }

    if (ds_buying.getRowCount() == 0 || ds_selling.getRowCount() > 0) {
        await $c.win.alert("buying 데이터가 없거나, selling 데이터가 이미 있는 경우는 해당 기능을 사용할 수 없습니다");
        //return false;
    }


    var thcCnt = 0;     // THC코드 count
    var thcIndex = -1;  // THC코드 selling rowIndex
    var ocfCnt = 0;     // OCF코드 count
    var ocfIndex = -1;  // OCF코드 selling rowIndex
    var slcChg = 0;     // SLC 코드 비용

    var hbPos = ds_houseblList.getRowPosition();
    var incoterms = ds_houseblList.getCellData(hbPos, "hhincoterm"); // Incoterms



    // selling row 생성
    function newSellingRow() {
        return ds_selling.insertRow(ds_selling.getRowCount());
    }


    // ds_SellingCode 0행 → selling row에 공통코드 컬럼 세팅
    function applySellingCodeToRow(sellRow) {
        ds_selling.setCellData(sellRow, "fareEngCd", ds_SellingCode.getCellData(0, "col1"));
        ds_selling.setCellData(sellRow, "sellItemCd", ds_SellingCode.getCellData(0, "col4"));
        ds_selling.setCellData(sellRow, "fareEngNm", ds_SellingCode.getCellData(0, "col2"));
        ds_selling.setCellData(sellRow, "fareGrpCd", ds_SellingCode.getCellData(0, "col6"));
        ds_selling.setCellData(sellRow, "vatYn", ds_SellingCode.getCellData(0, "col8"));
    }


    // 구매 데이터 loop (0-based)
    for (var i = 0; i < ds_buying.getRowCount(); i++) {

        var code = String(ds_buying.getCellData(i, "fareEngCd") || "");
        var last = code.substring(code.length - 1);

        // 전도금 계정이면 J,K 제외한 계정으로 입력
        if (last == "J" || last == "K") {
            code = code.substring(0, code.length - 1);
        }

        var totalAmt =
            Number(ds_buying.getCellData(i, "pchsAmt") || 0) +
            Number(ds_buying.getCellData(i, "vat") || 0);

        var crcCd = String(ds_buying.getCellData(i, "crcCd") || "");

        // 1) DOC : RATE 35,000원 고정
        if (code == "DOC") {

            var sellRow = newSellingRow();

            await f_commCodeAsync("ilCommonEBC", "retriveFreightCodeInfo", "DOC");
            applySellingCodeToRow(sellRow);

            ds_selling.setCellData(sellRow, "sellSeq", sellRow + 1);

            ds_selling.setCellData(sellRow, "crcCd", ds_buying.getCellData(i, "crcCd"));
            ds_selling.setCellData(sellRow, "fareUnit", ds_buying.getCellData(i, "fareUnit"));
            ds_selling.setCellData(sellRow, "chgWt", ds_buying.getCellData(i, "chgWt"));

            ds_selling.setCellData(sellRow, "sellUpr", 35000);

            var chgWt1 = Number(ds_buying.getCellData(i, "chgWt") || 0);
            ds_selling.setCellData(sellRow, "sellAmt", 35000 * chgWt1);

            ds_selling.setCellData(sellRow, "sellAmtFcrc", ds_buying.getCellData(i, "pchsAmtFcrc"));
            ds_selling.setCellData(sellRow, "exRate", ds_buying.getCellData(i, "exRate"));
            ds_selling.setCellData(sellRow, "trfUpr", ds_buying.getCellData(i, "trfUpr"));
            ds_selling.setCellData(sellRow, "usdAmt", ds_buying.getCellData(i, "usdAmt"));

            // 2) THC : 40FT/20FT(LCL) 에 따라 RATE 고정
        } else if (code == "THC") {

            var sellRow = newSellingRow();
            thcCnt += 1;
            thcIndex = sellRow;

            await f_commCodeAsync("ilCommonEBC", "retriveFreightCodeInfo", "THC");
            applySellingCodeToRow(sellRow);

            ds_selling.setCellData(sellRow, "sellSeq", sellRow + 1);

            ds_selling.setCellData(sellRow, "crcCd", ds_buying.getCellData(i, "crcCd"));
            ds_selling.setCellData(sellRow, "fareUnit", ds_buying.getCellData(i, "fareUnit"));

            var fareUnit = String(ds_selling.getCellData(sellRow, "fareUnit") || "");
            var chgWt2 = Number(ds_buying.getCellData(i, "chgWt") || 0);

            if (fareUnit.substring(0, 1) == "4") {          // 40FT
                ds_selling.setCellData(sellRow, "sellUpr", 210486);
            } else {                                         // 20FT 또는 LCL
                ds_selling.setCellData(sellRow, "sellUpr", 150243);
            }

            var sellUpr2 = Number(ds_selling.getCellData(sellRow, "sellUpr") || 0);
            ds_selling.setCellData(sellRow, "sellAmt", sellUpr2 * chgWt2);

            ds_selling.setCellData(sellRow, "chgWt", ds_buying.getCellData(i, "chgWt"));
            ds_selling.setCellData(sellRow, "sellAmtFcrc", ds_buying.getCellData(i, "pchsAmtFcrc"));
            ds_selling.setCellData(sellRow, "exRate", ds_buying.getCellData(i, "exRate"));
            ds_selling.setCellData(sellRow, "vatAmt", ds_buying.getCellData(i, "vat"));
            ds_selling.setCellData(sellRow, "trfUpr", ds_buying.getCellData(i, "trfUpr"));
            ds_selling.setCellData(sellRow, "usdAmt", ds_buying.getCellData(i, "usdAmt"));

            // 3) OCF 또는 (CIF & USD & code != AMS) : OCF로 합산
        } else if (code == "OCF" || (incoterms == "CIF" && crcCd == "USD" && code != "AMS")) {

            if (ocfCnt == 0) {

                var sellRow = newSellingRow();
                ocfCnt += 1;
                ocfIndex = sellRow;

                await f_commCodeAsync("ilCommonEBC", "retriveFreightCodeInfo", "OCF");
                applySellingCodeToRow(sellRow);

                ds_selling.setCellData(sellRow, "sellSeq", sellRow + 1);

                ds_selling.setCellData(sellRow, "crcCd", ds_buying.getCellData(i, "crcCd"));
                ds_selling.setCellData(sellRow, "fareUnit", ds_buying.getCellData(i, "fareUnit"));
                ds_selling.setCellData(sellRow, "chgWt", ds_buying.getCellData(i, "chgWt"));
                ds_selling.setCellData(sellRow, "sellAmtFcrc", ds_buying.getCellData(i, "pchsAmtFcrc"));
                ds_selling.setCellData(sellRow, "exRate", ds_buying.getCellData(i, "exRate"));

                ds_selling.setCellData(sellRow, "sellAmt", totalAmt);

                var chgWt3 = Number(ds_selling.getCellData(sellRow, "chgWt") || 0);
                if (String(ds_buying.getCellData(i, "crcCd") || "") == "KRW") {
                    ds_selling.setCellData(sellRow, "sellUpr", chgWt3 ? (totalAmt / chgWt3) : 0);
                } else {
                    ds_selling.setCellData(sellRow, "sellUpr", ds_buying.getCellData(i, "pchsUpr"));
                }

                ds_selling.setCellData(sellRow, "trfUpr", ds_buying.getCellData(i, "trfUpr"));
                ds_selling.setCellData(sellRow, "usdAmt", ds_buying.getCellData(i, "usdAmt"));

            } else {
                ds_selling.setCellData(ocfIndex, "sellAmt",
                    Number(ds_selling.getCellData(ocfIndex, "sellAmt") || 0) + totalAmt
                );
                ds_selling.setCellData(ocfIndex, "sellUpr",
                    Number(ds_selling.getCellData(ocfIndex, "sellUpr") || 0) + Number(ds_buying.getCellData(i, "pchsUpr") || 0)
                );
            }

            // 4) WFG : LOADING 값에 따라 RATE 고정(또는 totalAmt)
        } else if (code == "WFG") {

            var sellRow = newSellingRow();

            await f_commCodeAsync("ilCommonEBC", "retriveFreightCodeInfo", "WFG");
            applySellingCodeToRow(sellRow);

            ds_selling.setCellData(sellRow, "sellSeq", sellRow + 1);

            ds_selling.setCellData(sellRow, "crcCd", ds_buying.getCellData(i, "crcCd"));
            ds_selling.setCellData(sellRow, "fareUnit", ds_buying.getCellData(i, "fareUnit"));
            ds_selling.setCellData(sellRow, "chgWt", ds_buying.getCellData(i, "chgWt"));
            ds_selling.setCellData(sellRow, "sellAmtFcrc", ds_buying.getCellData(i, "pchsAmtFcrc"));
            ds_selling.setCellData(sellRow, "exRate", ds_buying.getCellData(i, "exRate"));

            var hhlodcd = String(ds_houseblList.getCellData(hbPos, "hhlodcd") || "");
            var fareUnitW = String(ds_selling.getCellData(sellRow, "fareUnit") || "");
            var chgWt4 = Number(ds_buying.getCellData(i, "chgWt") || 0);

            if (hhlodcd == "KRPUS") {
                ds_selling.setCellData(sellRow, "sellUpr", fareUnitW.substring(0, 1) == "4" ? 9030 : 4515);
                ds_selling.setCellData(sellRow, "sellAmt", Number(ds_selling.getCellData(sellRow, "sellUpr") || 0) * chgWt4);

            } else if (hhlodcd == "KRUSN" || hhlodcd == "KRKY") {
                ds_selling.setCellData(sellRow, "sellUpr", fareUnitW.substring(0, 1) == "4" ? 2912 : 1456);
                ds_selling.setCellData(sellRow, "sellAmt", Number(ds_selling.getCellData(sellRow, "sellUpr") || 0) * chgWt4);

            } else {
                ds_selling.setCellData(sellRow, "sellAmt", totalAmt);
                var chgWt4b = Number(ds_selling.getCellData(sellRow, "chgWt") || 0);
                ds_selling.setCellData(sellRow, "sellUpr", chgWt4b ? (totalAmt / chgWt4b) : 0);
            }

            ds_selling.setCellData(sellRow, "trfUpr", ds_buying.getCellData(i, "trfUpr"));
            ds_selling.setCellData(sellRow, "usdAmt", ds_buying.getCellData(i, "usdAmt"));

            // CIF & AMS
        } else if (incoterms == "CIF" && code == "AMS") {

            var sellRow = newSellingRow();

            await f_commCodeAsync("ilCommonEBC", "retriveFreightCodeInfo", "AMS");
            applySellingCodeToRow(sellRow);

            ds_selling.setCellData(sellRow, "sellSeq", sellRow + 1);

            ds_selling.setCellData(sellRow, "crcCd", ds_buying.getCellData(i, "crcCd"));
            ds_selling.setCellData(sellRow, "fareUnit", ds_buying.getCellData(i, "fareUnit"));
            ds_selling.setCellData(sellRow, "chgWt", ds_buying.getCellData(i, "chgWt"));
            ds_selling.setCellData(sellRow, "sellAmtFcrc", ds_buying.getCellData(i, "pchsAmtFcrc"));
            ds_selling.setCellData(sellRow, "exRate", ds_buying.getCellData(i, "exRate"));

            ds_selling.setCellData(sellRow, "sellAmt", totalAmt);

            var chgWt5 = Number(ds_selling.getCellData(sellRow, "chgWt") || 0);
            if (String(ds_buying.getCellData(i, "crcCd") || "") == "KRW") {
                ds_selling.setCellData(sellRow, "sellUpr", chgWt5 ? (totalAmt / chgWt5) : 0);
            } else {
                ds_selling.setCellData(sellRow, "sellUpr", ds_buying.getCellData(i, "pchsUpr"));
            }

            ds_selling.setCellData(sellRow, "trfUpr", ds_buying.getCellData(i, "trfUpr"));
            ds_selling.setCellData(sellRow, "usdAmt", ds_buying.getCellData(i, "usdAmt"));

            // CIF & SLC : SLC 금액 제외(누적)
        } else if (incoterms == "CIF" && code == "SLC") {
            slcChg += totalAmt;
        }
    }

    // 합계 계산(원본 NameSum 대체)
    function sumCol(ds, colId) {
        var sum = 0;
        for (var r = 0; r < ds.getRowCount(); r++) sum += Number(ds.getCellData(r, colId) || 0);
        return sum;
    }

    var sellingBuyingDiff =
        (sumCol(ds_buying, "pchsAmt") + sumCol(ds_buying, "vat"))
        - sumCol(ds_selling, "sellAmt")
        - slcChg;

    // CIF가 아닐때 잔액은 OTH로 기재
    if (sellingBuyingDiff > 0 && incoterms != "CIF") {

        var sellRow = newSellingRow();

        await f_commCodeAsync("ilCommonEBC", "retriveFreightCodeInfo", "OTH");
        applySellingCodeToRow(sellRow);

        ds_selling.setCellData(sellRow, "sellSeq", sellRow + 1);

        ds_selling.setCellData(sellRow, "crcCd", "KRW");
        ds_selling.setCellData(sellRow, "fareUnit", "CASE");
        ds_selling.setCellData(sellRow, "chgWt", 1);

        ds_selling.setCellData(sellRow, "sellAmt", sellingBuyingDiff);
        ds_selling.setCellData(sellRow, "sellUpr", sellingBuyingDiff);

        ds_selling.setCellData(sellRow, "sellAmtFcrc", 0);
        ds_selling.setCellData(sellRow, "exRate", 0);
        ds_selling.setCellData(sellRow, "trfUpr", 0);

        // 원본은 루프 i 의존(마지막 행) → 마지막 buying 행 usdAmt로 맞춤
        ds_selling.setCellData(
            sellRow,
            "usdAmt",
            ds_buying.getRowCount() > 0 ? ds_buying.getCellData(ds_buying.getRowCount() - 1, "usdAmt") : 0
        );
    }

    tac_tabMain.setSelectedTabIndex(0);;
    return true;
};

scwin.f_RunExcel1 = function () {
