    var hx = String(ds_houseblList.getCellData(r, "hhexrate") || "0");
    if (hx != "0") {
        scwin.exRate1 = ds_houseblList.getCellData(r, "hhexrate");
        scwin.crc = ds_houseblList.getCellData(r, "hhcur");
        scwin.exRateCheck = "3";
