//-------------------------------------------------------------------------
// Grid Popup (No global hook version)
//-------------------------------------------------------------------------
//tobe 추가: 시점문제로 인해 이전 기능 파라미터 추가. 
scwin.f_PopUpGrid = async function (disGubun, rowIdx, pWinCloseTF, pAllSearchTF, beforFuc, cd, nm) {
    scwin.row = rowIdx;
    var Row = rowIdx;
    switch (disGubun) {
        case "SellingCustomer":
            udc_ilcomCode.setSelectId("retrieveEngClntInfo");
            await udc_ilcomCode.ilCommonPopUp(function (rtnList) {
                $c.gus.cfSetGridReturnValue(rtnList, ds_selling, Row, "bilgClntNo", "bilgClntNm");
            }
                , cd //ds_selling.getCellData(Row, "bilgClntNo")	 //코드
                , nm || ds_selling.getCellData(Row, "bilgClntNm") 	 //코드명
                , pWinCloseTF		// 결과가 1건 일때	원도우를	AutoClose 여부	(T:Close,F:Opened)
                , '10'				// 검색	결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 -	default	(2)
                , 'Partner Code,Partner Name,Address1,Address2,Address3,Address4,Tel,,,CRN'  // Title순서
                , '140,300,100,100,100,100,100,,,100'                      // 보여주는 각 컬럼들의 	폭
                , '8,9'              // 컬럼중에서 숨기는	컬럼 지정
                , null				// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null				// POP-UP뛰을때	원도우의	사용자 정의	폭
                , null				// POP-UP뛰을때	우도우의	사용자 정의	높이
                , null				// 윈도우 위치 Y좌표
                , null				// 윈도우 위치 X좌표
                , null				// 중복체크여부	("F")
                , pAllSearchTF		// 전체검색허용여부	("F")
                , 'Customer search,Customer Code,Customer Name'	// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                , 'F'				// Data	건수가 0 일때 Window를 뛰우지 않음 리턴	: "N/A"
            );
            break;

        case "SellingFcode":
            udc_ilcomCode.setSelectId("retriveFreightCodeInfo");
            await udc_ilcomCode.ilCommonPopUp(async function (rtnList) {
                await $c.gus.cfSetGridReturnValue(rtnList, ds_selling, Row, "fareEngCd", "fareEngNm");
                if (undefined == rtnList) {
                    return false;
                }
                ds_selling.setCellData(Row, "sellItemCd", rtnList[3]);
                ds_selling.setCellData(Row, "fareGrpCd", rtnList[5]);
                ds_selling.setCellData(Row, "vatYn", rtnList[7]);
                if (rtnList[9] == "1") { //원화.
                    ds_selling.setCellData(Row, "crcCd", "KRW");
                } else {
                    ds_selling.setCellData(Row, "crcCd", ed_hhcur.getValue());
                }
                if (ds_selling.getCellData(Row, "fareEngCd") == "OCF") {
                    ds_selling.setCellData(Row, "crcCd", "USD");
                }

                //tobe 변경
                if (beforFuc == "afteredit") {
                    await scwin.f_sellingAmtFcrc(Row, "fareEngCd", ds_selling.getCellData(Row, "fareEngCd"));
                    await scwin.f_sellingAmt(Row, "fareEngCd", ds_selling.getCellData(Row, "fareEngCd"));
                    await scwin.f_sellingVat(Row, "fareEngCd", ds_selling.getCellData(Row, "fareEngCd"));
                    scwin.f_sellingUsdAmt(Row, "fareEngCd", ds_selling.getCellData(Row, "fareEngCd"));
                } else if (beforFuc == "retrieveTariff_onsubmit") {
                    ds_selling.setCellData(r, "crcCd", ds_resultTariff.getCellData(i, "crcCd"));
                    ds_selling.setCellData(r, "fareUnit", ds_resultTariff.getCellData(i, "fareUnit"));

                    await scwin.f_packageRateSellingLoading(r, "");
                    ds_selling.setCellData(r, "sellUpr", ds_resultTariff.getCellData(i, "amount"));

                    await scwin.f_sellingAmtFcrc(r, "", "");
                    await scwin.f_ExRateSellingGridLoading();
                    await scwin.f_sellingAmt(r, "", "");
                    await scwin.f_sellingVat(r, "", "");
                    scwin.f_sellingUsdAmt(r, "", "");
                }
            }
                , cd//ds_selling.getCellData(Row, "fareEngCd")	 //코드
                , nm || ds_selling.getCellData(Row, "fareEngNm") 	 //코드명
                , pWinCloseTF		// 결과가 1건 일때	원도우를	AutoClose 여부	(T:Close,F:Opened)
                , '2'				// 검색	결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 -	default	(2)
                , "Code, Name"		// Title순서
                , '80,230'			// 보여주는	각 컬럼들의	폭
                , "3,4,5,6,7,8,9,10"	// 컬럼중에서 숨기는	컬럼 지정
                , "S,1"				// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null				// POP-UP뛰을때	원도우의	사용자 정의	폭
                , null				// POP-UP뛰을때	우도우의	사용자 정의	높이
                , null				// 윈도우 위치 Y좌표
                , null				// 윈도우 위치 X좌표
