//for=gr_selling event=OnPopup(Row,Colid,data)
scwin.gr_selling_ontextimageclick = function (rowIndex, columnIndex) {
    var row = rowIndex;
    var col = gr_selling.getColumnID(columnIndex);

    var cd = "";
    var nm = "";

    switch (col) {
        case "bilgClntNo":
            cd = ds_selling.getCellData(rowIndex, "bilgClntNo")	 //코드
            if (cd != "") nm = ds_selling.getCellData(rowIndex, "bilgClntNm") 	 //코드명

            ds_selling.setCellData(rowIndex, "bilgClntNo", "");
            ds_selling.setCellData(rowIndex, "bilgClntNm", "");

            scwin.f_PopUpGrid("SellingCustomer", row, "F", "F", "", cd, nm);
            break;
        case "fareEngCd":
            cd = ds_selling.getCellData(rowIndex, "fareEngCd")	 //코드
            if (cd != "") nm = ds_selling.getCellData(rowIndex, "fareEngNm")

            ds_selling.setCellData(rowIndex, "fareEngCd", "");
            ds_selling.setCellData(rowIndex, "fareEngNm", "");

            scwin.f_PopUpGrid("SellingFcode", row, "F", "F", "", cd, nm);
            break;
        case "rsltsStdDt":
            //$c.gus.cfOpenCalendar(gr_selling, row, col);
            break;
    }
};

//event=OnExit(Row,Colid,olddata)
scwin.gr_selling_onafteredit = async function (rowIndex, columnIndex, value) {
    if (document.activeElement.getAttribute('data-inputtype') == 'textImage' &&
        document.activeElement.getAttribute('data-colindex') == columnIndex + 1) return;

    var row = rowIndex;
    var col = gr_selling.getColumnID(columnIndex);
    var olddata = ds_selling.getCellData(row, col);

    var cd = "";
    var nm = "";

    if (row < 0 || ds_selling.getRowCount() <= row) return;

    switch (col) {

        case "bilgClntNo":
            if (ds_selling.getCellData(rowIndex, col).trim() != "") {
                cd = ds_selling.getCellData(rowIndex, "bilgClntNo")	 //코드
                // nm = ds_selling.getCellData(rowIndex, "bilgClntNm") 	 //코드명

                ds_selling.setCellData(rowIndex, "bilgClntNo", "");
                ds_selling.setCellData(rowIndex, "bilgClntNm", "");

                await scwin.f_PopUpGrid("SellingCustomer", row, "T", "F", "", cd, nm);
            } else {
                ds_selling.setCellData(row, "bilgClntNo", "");
                ds_selling.setCellData(row, "bilgClntNm", "");
            }
            break;

        case "fareEngCd":
            if (ds_selling.getCellData(row, col).trim() != "") {
                cd = ds_selling.getCellData(rowIndex, "fareEngCd")	 //코드
                //nm = ds_selling.getCellData(rowIndex, "fareEngNm")

                ds_selling.setCellData(rowIndex, "fareEngCd", "");
                ds_selling.setCellData(rowIndex, "fareEngNm", "");

                //await scwin.f_PopUpGrid("SellingFcode", row, "T", "F", "F");
                await scwin.f_PopUpGrid("SellingFcode", row, "T", "F", "afteredit", cd, nm);

            } else if (ds_selling.getCellData(row, col).trim() == "") {
                ds_selling.setCellData(row, "fareEngCd", "");
                ds_selling.setCellData(row, "fareEngNm", "");

                await scwin.f_sellingAmtFcrc(row, col, olddata);
                await scwin.f_sellingAmt(row, col, olddata);
                await scwin.f_sellingVat(row, col, olddata);
                scwin.f_sellingUsdAmt(row, col, olddata);
            }

            // tobe변경 : 시점문제로 위치 변경
            // await scwin.f_sellingAmtFcrc(row, col, olddata); 
            // await scwin.f_sellingAmt(row, col, olddata);
            // await scwin.f_sellingVat(row, col, olddata);
            // scwin.f_sellingUsdAmt(row, col, olddata);

            break;

        case "crcCd":
        case "chgWt":
        case "sellUpr":
            await scwin.f_sellingAmtFcrc(row, col, olddata);
            await scwin.f_sellingAmt(row, col, olddata);
            await scwin.f_sellingVat(row, col, olddata);
            await scwin.f_sellingUsdAmt(row, col, olddata);
            break;

        case "exRate":
            scwin.f_sellingAmt(row, col, olddata);
            break;

        case "sellAmt":
