//==========================
// [공통] DataList RowCount/RowPosition/Cell getter 호환
//==========================
scwin._rowCount = function (ds) {
    if (!ds) return 0;
    if (typeof ds.getRowCount == "function") return ds.getRowCount();
    if (ds.CountRow != undefined) return Number(ds.CountRow) || 0;
    return 0;
};
scwin._rowPos = function (ds) {
    if (!ds) return -1;
    if (typeof ds.getRowPosition == "function") return ds.getRowPosition();
    if (ds.RowPosition != undefined) return Number(ds.RowPosition) || 0;
    return 0;
};
scwin._get = function (ds, row, col) {
    if (!ds) return "";
    if (typeof ds.getCellData == "function") return ds.getCellData(row, col);
    // GAUCE NameValue(1-based)였던 경우가 섞여있으면 프로젝트에서 통일 필요
    return "";
};
scwin._set = function (ds, row, col, val) {
    if (!ds) return;
    if (typeof ds.setCellData == "function") ds.setCellData(row, col, val);
};

