//event=OnExit(Row,Colid,olddata)
scwin.gr_partner_onafteredit = async function (rowIndex, columnIndex, value) {
    if (document.activeElement.getAttribute('data-inputtype') == 'textImage' &&
        document.activeElement.getAttribute('data-colindex') == columnIndex + 1) return;

    var col = gr_partner.getColumnID(columnIndex);
    var olddata = ds_partner.getCellData(rowIndex, col);

    var cd = "";
    var nm = "";

    if (rowIndex < 0 || scwin._rowCount(ds_partner) < rowIndex) return;

    switch (col) {
        case "bilgClntNo":
            if (ds_partner.getCellData(rowIndex, col).trim() != "") {
                cd = ds_partner.getCellData(rowIndex, "bilgClntNo")	 //코드
                //nm = ds_partner.getCellData(rowIndex, "bilgClntNm") 	 //코드명

                ds_partner.setCellData(rowIndex, "bilgClntNo", "");
                ds_partner.setCellData(rowIndex, "bilgClntNm", "");

                //await scwin.f_PopUpGrid("PartnerCustomer", row, "T", "F", "F");
                await scwin.f_PopUpGrid("PartnerCustomer", rowIndex, "T", "F", "", cd, nm);
            } else {
                ds_partner.setCellData(rowIndex, "bilgClntNo", "");
                ds_partner.setCellData(rowIndex, "bilgClntNm", "");
            }
            break;

        case "fareEngCd":
            if (ds_partner.getCellData(rowIndex, col).trim() != "") {
                cd = ds_partner.getCellData(rowIndex, "fareEngCd")	 //코드
                //nm = ds_partner.getCellData(rowIndex, "fareEngNm")

                ds_partner.setCellData(rowIndex, "fareEngCd", "");
                ds_partner.setCellData(rowIndex, "fareEngNm", "");

                //await scwin.f_PopUpGrid("PartnerFcode", row, "T", "F", "F");
                await scwin.f_PopUpGrid("PartnerFcode", rowIndex, "T", "F", "afteredit", cd, nm);

            } else {
                ds_partner.setCellData(rowIndex, "fareEngCd", "");
                ds_partner.setCellData(rowIndex, "fareEngNm", "");

                await scwin.f_partnerAmtFcrc(rowIndex, col, olddata);
                await scwin.f_partnerAmt(rowIndex, col, olddata);
                scwin.f_partnerUsdAmt(rowIndex, col, olddata);
            }

            // tobe변경 : 시점문제로 위치 변경
            // await scwin.f_partnerAmtFcrc(row, col, olddata);
            // await scwin.f_partnerAmt(row, col, olddata);
            // scwin.f_partnerUsdAmt(row, col, olddata);

            break;

        case "crcCd":
        case "chgWt":
        case "sellUpr":
            await scwin.f_partnerAmtFcrc(rowIndex, col, olddata);
            await scwin.f_partnerAmt(rowIndex, col, olddata);
            scwin.f_partnerUsdAmt(rowIndex, col, olddata);
            break;

        case "exRate":
            scwin.f_partnerAmt(rowIndex, col, olddata);
            break;

        case "sellAmt":
            scwin.f_partnerUsdAmt(rowIndex, col, olddata);
            break;

        case "fareUnit":
            await scwin.f_packageRatePartnerLoading(rowIndex, col);
            scwin.f_partnerTariffRateLoading();
            break;
    }
};

