                cd = ds_buying.getCellData(rowIndex, "pchsClntNo")	 //코드

                ds_buying.setCellData(rowIndex, "pchsClntNo", "");
                ds_buying.setCellData(rowIndex, "pchsClntNm", "");

                scwin.f_PopUpGrid("BuyingCustomer", rowIndex, "T", "F", "", cd);
            } else {
                ds_buying.setCellData(rowIndex, "pchsClntNo", "");
                ds_buying.setCellData(rowIndex, "pchsClntNm", "");
            }
            break;

        case "fareEngCd":
            if (ds_buying.getCellData(rowIndex, col).trim() != "") {
                cd = ds_buying.getCellData(rowIndex, "fareEngCd")	 //코드

                ds_buying.setCellData(rowIndex, "fareEngCd", "");
                ds_buying.setCellData(rowIndex, "fareEngNm", "");

                await scwin.f_PopUpGrid("BuyingFcode", rowIndex, "T", "F", "afterEidt", cd);

            } else {
                ds_buying.setCellData(rowIndex, "fareEngCd", "");
                ds_buying.setCellData(rowIndex, "fareEngNm", "");

                // 원본: pchsTyp==3 && fareEngCd==TRD면 dept loading
                if (ds_buying.getCellData(rowIndex, "pchsTyp") == "3") {
                    if (ds_buying.getCellData(rowIndex, "fareEngCd") == "TRD") {
                        scwin.f_BuyingDeptLoading(rowIndex);
                    }
                }

                if (scwin.v_linkcheck == "" || scwin.v_linkcheck != 9) {
                    scwin.f_buyingAmtFcrc(rowIndex, col, olddata);
                    scwin.f_buyingAmt(rowIndex, col, olddata);
                    scwin.f_buyingVat(rowIndex, col, olddata);
                    scwin.f_buyingUsdAmt(rowIndex, col, olddata);
                }
            }

            // tobe변경 : 시점문제로 위치 변경
            // 원본: pchsTyp==3 && fareEngCd==TRD면 dept loading
            // if (String(scwin._get(ds_buying, row, "pchsTyp")) == "3") {
            //     if (String(scwin._get(ds_buying, row, "fareEngCd")) == "TRD") {
            //         scwin.f_BuyingDeptLoading(row);
            //     }
            // }

            // if (scwin.v_linkcheck == "" || scwin.v_linkcheck != 9) {
            //     scwin.f_buyingAmtFcrc(row, col, olddata);
            //     scwin.f_buyingAmt(row, col, olddata);
            //     scwin.f_buyingVat(row, col, olddata);
            //     scwin.f_buyingUsdAmt(row, col, olddata);
            // }


            break;

        case "sellDeptCd":
            if (ds_buying.getCellData(rowIndex, col).trim() != "") {
                cd = ds_buying.getCellData(rowIndex, "sellDeptCd")	 //코드

                ds_buying.setCellData(rowIndex, "sellDeptCd", "");
                ds_buying.setCellData(rowIndex, "sellDeptNm", "");

                scwin.f_PopUpGrid("BuyingDept", rowIndex, "T", "F", "", cd);
            } else {
                ds_buying.setCellData(rowIndex, "sellDeptCd", "");
                ds_buying.setCellData(rowIndex, "sellDeptNm", "");
            }
            break;

        case "crcCd":
        case "chgWt":
        case "pchsUpr":
            scwin.f_buyingAmtFcrc(rowIndex, col, olddata);
            scwin.f_buyingAmt(rowIndex, col, olddata);
            scwin.f_buyingVat(rowIndex, col, olddata);
            scwin.f_buyingUsdAmt(rowIndex, col, olddata);
            break;

        case "exRate":
            scwin.f_buyingAmt(rowIndex, col, olddata);
            break;

        case "pchsAmt":
            scwin.f_buyingVat(rowIndex, col, olddata);
            break;

        case "vat":
            scwin.f_buyingUsdAmt(rowIndex, col, olddata);
            break;

        case "fareUnit":
            scwin.f_packageRateBuyingLoading(rowIndex, col);
            scwin.f_buyingTariffRateLoading();
            break;

        case "pchsTyp":
            // 내부부서일때 원본 로직 유지
            var pchsTyp = ds_buying.getCellData(rowIndex, "pchsTyp");
            if (pchsTyp == "3") {
                ds_buying.setCellData(rowIndex, "pchsClntNo", scwin.p_clntNo);
                cd = ds_buying.getCellData(rowIndex, "pchsClntNo")	 //코드

                ds_buying.setCellData(rowIndex, "pchsClntNo", "");
                ds_buying.setCellData(rowIndex, "pchsClntNm", "");

                scwin.f_PopUpGrid("BuyingCustomer", rowIndex, "T", "F", "", cd);
            } else {
                ds_buying.setCellData(rowIndex, "pchsClntNo", "");
                ds_buying.setCellData(rowIndex, "pchsClntNm", "");
            }

            break;
    }
};

